mapper.insert:
/*
     SQL ID : ApiDAO.insertZipcontUploadLog
     설 명 : ZIP 콘텐츠 업로드 로그 저장
*/
INSERT INTO TB_LOG_ZIPCONTENT_UPLOAD (
    ZIPCONTENT_LOG_SN
    , CURRI_CODE
    , WEEK
    , PAGE_SEQ
    , UPLOAD_PATH
    , UPLOAD_FILE_NM
    , UPLOAD_SIZE
    , RGTR_ID
    , FRST_INQ_DTTM
) VALUES (
    #{zipcontentLogSn}
    , #{curriCode}
    , #{week}
    , #{pageSeq}
    , #{uploadPath}
    , #{uploadFileNm}
    , #{uploadSize}
    , #{rgtrId}
    , FN_DTTM()
)

mapper.select:
/* SQL ID : ApiDAO.selectStuNoticeCountInfo 설 명 : 강의공지 읽지않은 건수 : NOTICE */ SELECT COUNT(1) AS COUNT_INFO FROM ( SELECT IF(EXISTS(SELECT 1 FROM TB_LMS_BBS_ATCL_INQ_RCD WHERE ATCL_ID = A.ATCL_ID AND USER_ID = #{userId}), 'Y', 'N') AS INQYN FROM TB_LMS_BBS_ATCL A JOIN TB_LMS_BBS B ON A.BBS_ID = B.BBS_ID AND B.DELYN = 'N' AND B.USEYN = 'Y' AND B.SYS_BSC_PVSNYN = 'Y' AND B.BBS_ID = 'NOTICE' AND B.ORG_ID = #{orgId} JOIN TB_HOME_BBS_RLTN C ON B.BBS_ID = C.BBS_ID AND C.CONTS_TYCD = 'COURSE' AND C.RLTN_REF_CD IN ( SELECT A.SBJCT_ID FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' AND B.USER_ID = #{userId} AND B.ORG_ID = #{orgId} JOIN TB_LMS_TERM_CRE_CRS_RLTN C ON A.SBJCT_ID = C.SBJCT_ID JOIN CRS_SMSTR D ON C.CRS_SMSTR_ID = D.CRS_SMSTR_ID AND D.OP_SDTTM <= FN_DTTM() WHERE A.DELYN = 'N' AND A.CRS_ID NOT LIKE '%JLPT%'
AND A.SBJCT_ID = #{year}
AND A.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y'))) AND ORG_ID = #{orgId}
AND A.CRS_ID = #{semester}
AND A.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y'))) AND ORG_ID = #{orgId}
AND A.CRS_ID = #{courseCode}
AND A.SBJCT_ID = #{crsCreCd}
AND A.DVCLAS_NO = #{section}
) WHERE A.DELYN = 'N' AND A.UP_ATCL_ID IS NULL AND ( A.RSRV_USEYN = 'N' OR A.RSRV_DTTM <= FN_DTTM() ) AND A.LOCKYN = 'N' ) A WHERE INQYN = 'N'

/* SQL ID : ApiDAO.selectStuQnaCountInfo 설 명 : QNA 읽지 않은 건수 : QNA */ SELECT COUNT(1) AS COUNT_INFO FROM ( SELECT D.ATCL_ID , (SELECT COUNT(1) FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = D.ATCL_ID AND DELYN = 'N') AS ANS_CNT , ( SELECT COUNT(1) FROM TB_LMS_BBS_ATCL AA JOIN TB_LMS_BBS_ATCL_INQ_RCD BB ON AA.ATCL_ID = BB.ATCL_ID AND BB.USER_ID = A.USER_ID WHERE AA.UP_ATCL_ID = D.ATCL_ID AND AA.DELYN = 'N' ) AS VIEW_CNT FROM ( SELECT A.SBJCT_ID , B.USER_ID FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' AND B.ATNDLC_ABNDYN = 'N' AND B.USER_ID = #{userId} AND B.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.CRS_ID NOT LIKE '%JLPT%'
AND A.SBJCT_ID = #{year}
AND A.SBJCT_ID = ( SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')) AND ORG_ID = #{orgId} )
AND A.CRS_ID = #{semester}
AND A.SBJCT_ID = ( SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')) AND ORG_ID = #{orgId} )
AND A.CRS_ID = #{courseCode}
AND A.SBJCT_ID = #{crsCreCd}
AND A.DVCLAS_NO = #{section}
) A JOIN TB_HOME_BBS_RLTN B ON A.SBJCT_ID = B.RLTN_REF_CD AND B.CONTS_TYCD = 'COURSE' JOIN TB_LMS_BBS C ON B.BBS_ID = C.BBS_ID AND C.DELYN = 'N' AND C.USEYN = 'Y' AND C.SYS_BSC_PVSNYN = 'Y' AND C.BBS_ID = 'QNA' AND C.ORG_ID = #{orgId} JOIN TB_LMS_BBS_ATCL D ON B.BBS_ID = D.BBS_ID AND D.DELYN = 'N' AND D.UP_ATCL_ID IS NULL AND D.RGTR_ID = A.USER_ID ORDER BY D.FRST_INQ_DTTM DESC LIMIT 5 ) A WHERE A.ANS_CNT - A.VIEW_CNT != 0

/* SQL ID : ApiDAO.selectStuSecretCountInfo 설 명 : 1:1 상담 읽지않은 건수 : SECRET */ SELECT COUNT(1) AS COUNT_INFO FROM ( SELECT D.ATCL_ID , (SELECT COUNT(1) FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = D.ATCL_ID AND DELYN = 'N') AS ANS_CNT , ( SELECT COUNT(1) FROM TB_LMS_BBS_ATCL AA JOIN TB_LMS_BBS_ATCL_INQ_RCD BB ON AA.ATCL_ID = BB.ATCL_ID AND BB.USER_ID = A.USER_ID WHERE AA.UP_ATCL_ID = D.ATCL_ID AND AA.DELYN = 'N' ) AS VIEW_CNT FROM ( SELECT A.SBJCT_ID , B.USER_ID FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' AND B.ATNDLC_ABNDYN = 'N' AND B.USER_ID = #{userId} AND B.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.CRS_ID NOT LIKE '%JLPT%'
AND A.SBJCT_ID = #{year}
AND A.SBJCT_ID = ( SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')) AND ORG_ID = #{orgId} )
AND A.CRS_ID = #{semester}
AND A.SBJCT_ID = ( SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')) AND ORG_ID = #{orgId} )
AND A.CRS_ID = #{courseCode}
AND A.SBJCT_ID = #{crsCreCd}
AND A.DVCLAS_NO = #{section}
) A JOIN TB_HOME_BBS_RLTN B ON A.SBJCT_ID = B.RLTN_REF_CD AND B.CONTS_TYCD = 'COURSE' JOIN TB_LMS_BBS C ON B.BBS_ID = C.BBS_ID AND C.DELYN = 'N' AND C.USEYN = 'Y' AND C.SYS_BSC_PVSNYN = 'Y' AND C.BBS_ID = 'SECRET' AND C.ORG_ID = #{orgId} JOIN TB_LMS_BBS_ATCL D ON B.BBS_ID = D.BBS_ID AND D.DELYN = 'N' AND D.UP_ATCL_ID IS NULL AND D.RGTR_ID = A.USER_ID ORDER BY D.FRST_INQ_DTTM DESC LIMIT 5 ) A WHERE A.ANS_CNT - A.VIEW_CNT != 0

/* SQL ID : ApiDAO.selectStuAsmtCountInfo 설 명 : 과제 미제출 건수 */ SELECT COUNT(1) AS COUNT_INFO FROM ( SELECT IFNULL(C.SBMSN_STSCD, 'NO') AS SBMSN_STSCD , ( SELECT COUNT(1) FROM TB_LMS_EXAM_STARE AA JOIN TB_LMS_EXAM_BSC BB ON AA.EXAM_ID = BB.EXAM_ID AND BB.EXAM_CTGRCD = 'EXAM' AND BB.EXAM_TYCD = 'EXAM' AND BB.DELYN = 'N' AND BB.EXAM_SBST_REF_ID = A.ASMT_ID WHERE AA.DELYN = 'N' AND AA.REEXAMYN = 'Y' AND AA.STD_ID = B.STD_ID ) RECNT , ( SELECT COUNT(1) FROM TB_LMS_EXAM_BSC WHERE EXAM_CTGRCD = 'EXAM' AND EXAM_TYCD = 'EXAM' AND DELYN = 'N' AND EXAM_SBST_REF_ID = A.ASMT_ID ) INCNT FROM TB_LMS_ASMT A JOIN ( SELECT A.SBJCT_ID , B.STD_ID FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' AND B.USER_ID = #{userId} AND B.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND A.SBJCT_TYCD = 'UNI' AND A.CRS_ID NOT LIKE '%JLPT%'
AND A.SBJCT_ID = #{year}
AND A.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y'))) AND ORG_ID = #{orgId}
AND A.CRS_ID = #{semester}
AND A.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y'))) AND ORG_ID = #{orgId}
AND A.CRS_ID = #{courseCode}
AND A.SBJCT_ID = #{crsCreCd}
AND A.DVCLAS_NO = #{section}
) B ON A.SBJCT_ID = B.SBJCT_ID JOIN TB_LMS_ASMT_SBMSN C ON A.ASMT_ID = C.ASMT_ID AND B.STD_ID = C.STD_ID WHERE A.DELYN = 'N' AND A.ASMNT_OPEN_YN = 'Y' AND ( (C.RESEND_YN = 'Y' AND FN_DTTM() BETWEEN A.RESEND_START_DTTM AND A.RESEND_END_DTTM) OR (C.RESEND_YN = 'N' AND FN_DTTM() BETWEEN A.SEND_START_DTTM AND IF(A.EXT_SEND_ACPT_YN = 'Y', IFNULL(A.EXT_SEND_DTTM, A.SEND_END_DTTM) , A.SEND_END_DTTM)) ) ) A WHERE (A.RECNT > 0 OR A.INCNT = 0) AND A.SBMSN_STSCD = 'NO'

/* SQL ID : ApiDAO.selectStuForumCountInfo 설 명 : 토론 미제출 건수 */ SELECT COUNT(1) AS COUNT_INFO FROM ( SELECT A.SBJCT_ID , B.USER_ID , ( SELECT COUNT(1) FROM TB_LMS_EXAM_STARE AA JOIN TB_LMS_EXAM_BSC BB ON AA.EXAM_ID = BB.EXAM_ID AND BB.EXAM_CTGRCD = 'EXAM' AND BB.EXAM_TYCD = 'EXAM' AND BB.DELYN = 'N' AND BB.EXAM_SBST_REF_ID = C.DSCS_ID WHERE AA.DELYN = 'N' AND AA.REEXAMYN = 'Y' AND AA.STD_ID = B.STD_ID ) RECNT , ( SELECT COUNT(1) FROM TB_LMS_EXAM_BSC WHERE EXAM_CTGRCD = 'EXAM' AND EXAM_TYCD = 'EXAM' AND DELYN = 'N' AND EXAM_SBST_REF_ID = C.DSCS_ID ) INCNT FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' AND B.USER_ID = #{userId} AND B.ORG_ID = #{orgId} JOIN TB_LMS_DSCS C ON A.SBJCT_ID = C.SBJCT_ID AND C.DELYN = 'N' AND FN_DTTM() BETWEEN C.DSCS_SDTTM AND IF(IFNULL(C.PRD_AFTR_WRTYN, 'N') = 'Y', IFNULL(C.EXTD_EDTTM, C.DSCS_EDTTM), C.DSCS_EDTTM) AND NOT EXISTS ( SELECT 1 FROM TB_LMS_DSCS_ATCL X WHERE DSCS_ID = C.DSCS_ID AND DELYN = 'N' AND RGTR_ID = B.USER_ID ) WHERE A.DELYN = 'N' AND A.SBJCT_TYCD = 'UNI' AND A.CRS_ID NOT LIKE '%JLPT%'
AND A.DVCLAS_NO = #{section}
AND A.CRS_ID = #{courseCode}
AND A.SBJCT_ID = #{crsCreCd}
AND A.SBJCT_ID = #{year}
AND A.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y'))) AND ORG_ID = #{orgId}
AND A.CRS_ID = #{semester}
AND A.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y'))) AND ORG_ID = #{orgId}
) A WHERE (A.RECNT > 0 OR A.INCNT = 0)

/* SQL ID : ApiDAO.selectStuQuizCountInfo 설 명 : 퀴즈 미제출 건수 */ SELECT COUNT(1) AS COUNT_INFO FROM ( SELECT A.STD_ID , B.EXAM_ID , ( SELECT COUNT(1) CNT FROM TB_LMS_EXAM_STARE AA JOIN TB_LMS_EXAM_BSC BB ON AA.EXAM_ID = BB.EXAM_ID AND BB.EXAM_CTGRCD = 'EXAM' AND BB.EXAM_TYCD = 'EXAM' AND BB.DELYN = 'N' AND BB.EXAM_SBST_REF_ID = B.EXAM_ID WHERE AA.DELYN = 'N' AND AA.REEXAMYN = 'Y' AND AA.STD_ID = A.STD_ID ) RECNT , ( SELECT COUNT(1) FROM TB_LMS_EXAM_BSC WHERE EXAM_CTGRCD = 'EXAM' AND EXAM_TYCD = 'EXAM' AND DELYN = 'N' AND EXAM_SBST_REF_ID = B.EXAM_ID ) INCNT FROM ( SELECT A.SBJCT_ID , B.STD_ID FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' AND B.USER_ID = #{userId} AND B.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.SBJCT_TYCD = 'UNI' AND A.CRS_ID NOT LIKE '%JLPT%'
AND A.SBJCT_ID = #{year}
AND A.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y'))) AND ORG_ID = #{orgId}
AND A.CRS_ID = #{semester}
AND A.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y'))) AND ORG_ID = #{orgId}
AND A.DVCLAS_NO = #{section}
AND A.CRS_ID = #{courseCode}
AND A.SBJCT_ID = #{crsCreCd}
) A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' JOIN TB_LMS_EXAM_BSC C ON B.EXAM_ID = C.EXAM_ID AND C.EXAM_CTGRCD = 'QUIZ' AND C.DELYN = 'N' AND C.USEYN = 'Y' AND C.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') LEFT JOIN TB_LMS_EXAM_STARE D ON C.EXAM_ID = D.EXAM_ID AND A.STD_ID = D.STD_ID AND D.DELYN = 'N' WHERE ( (IFNULL(D.REEXAMYN, 'N') = 'Y' AND FN_DTTM() BETWEEN C.RE_EXAM_START_DTTM AND C.RE_EXAM_END_DTTM) OR (IFNULL(D.REEXAMYN, 'N') != 'Y' AND FN_DTTM() BETWEEN C.EXAM_SDTTM AND C.EXAM_EDTTM) ) ) A WHERE (A.RECNT > 0 OR A.INCNT = 0) AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_STARE WHERE EXAM_ID = A.EXAM_ID AND STD_ID = A.STD_ID AND DELYN = 'N' AND STARE_CNT > 0 AND SDTTM IS NOT NULL )

/* SQL ID : ApiDAO.selectStuReschCountInfo 설 명 : 설문 미제출 건수 */ SELECT COUNT(1) AS COUNT_INFO FROM ( SELECT A.SBJCT_ID , B.STD_ID , B.USER_ID FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' AND B.USER_ID = #{userId} AND B.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.SBJCT_TYCD = 'UNI' AND A.CRS_ID NOT LIKE '%JLPT%'
AND A.SBJCT_ID = #{year}
AND A.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y'))) AND ORG_ID = #{orgId}
AND A.CRS_ID = #{semester}
AND A.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y'))) AND ORG_ID = #{orgId}
AND A.DVCLAS_NO = #{section}
AND A.CRS_ID = #{courseCode}
AND A.SBJCT_ID = #{crsCreCd}
) A JOIN TB_LMS_RESCH_CRE_CRS_RLTN B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' JOIN TB_LMS_SRVY C ON B.SRVY_ID = C.SRVY_ID AND C.DELYN = 'N' AND C.USEYN = 'Y' AND C.SRVY_TMPLTYN = 'N' AND C.SRVY_QSTNS_CMPTNYN = 'Y' AND FN_DTTM() BETWEEN C.SRVY_SDTTM AND C.RESCH_END_DTTM AND NOT EXISTS ( SELECT 1 FROM TB_LMS_SRVY_RSPNS WHERE SRVY_ID = C.SRVY_ID AND USER_ID = A.USER_ID )

/* SQL ID : ApiDAO.selectProfBbsCountInfo 설 명 : 담당과목의 QNA 미답변 건수, 담당과목의 1:1 상담 미답변 건수 */ SELECT IFNULL(COUNT(1),0) AS COUNT_INFO FROM TB_LMS_BBS_ATCL THBA , TB_LMS_BBS THBI , TB_HOME_BBS_RLTN THBR , ( SELECT A.SBJCT_ID FROM TB_LMS_SBJCT A , SBJCT_PROF B , TB_LMS_TERM_CRE_CRS_RLTN C WHERE A.SBJCT_ID = B.SBJCT_ID AND A.SBJCT_ID = C.SBJCT_ID AND A.DELYN = 'N' AND A.USEYN = 'Y' AND B.USER_ID = #{userId} AND B.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT')
AND A.SBJCT_ID = #{year}
AND A.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND A.CRS_ID = #{semester}
AND A.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND A.CRS_ID = #{courseCode}
AND A.DVCLAS_NO = #{section}
AND A.SBJCT_ID = #{crsCreCd}
) TLCC WHERE THBA.BBS_ID = THBI.BBS_ID AND THBI.BBS_ID = #{alarmType} AND THBI.BBS_ID = THBR.BBS_ID AND TLCC.SBJCT_ID = THBR.RLTN_REF_CD AND THBR.CONTS_TYCD = 'COURSE' AND THBI.DELYN = 'N' AND THBI.USEYN = 'Y' AND THBI.SYS_BSC_PVSNYN = 'Y' AND THBI.ORG_ID = #{orgId} AND THBA.DELYN = 'N' AND THBA.UP_ATCL_ID IS NULL AND (SELECT COUNT(1) FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = THBA.ATCL_ID AND DELYN = 'N') = 0

/* SQL ID : ApiDAO.selectProfExamAbsentRequestCountInfo 설 명 : 신청받은 결시원 개수 */ WITH TB_SYS_JOB_SCH_T AS ( SELECT A.DGRS_YR , A.DGRS_SMSTR FROM TB_LMS_SYSJOB_SCHDL A WHERE A.SYSJOB_SCHDL_TYCD IN ('00190902', '00190903') AND A.ORG_ID = #{orgId} AND A.USEYN = 'Y' AND A.DGRS_YR = #{year} AND A.DGRS_SMSTR = #{semester} AND (DATE_FORMAT(NOW(), "%Y-%m-%d %T") BETWEEN DATE_FORMAT(A.SYSJOB_SCHDL_SYMD, "%Y-%m-%d %T") AND DATE_FORMAT(ADDDATE(A.SYSJOB_SCHDL_EYMD, INTERVAL 1 DAY), "%Y-%m-%d %T")) GROUP BY A.DGRS_YR, A.DGRS_SMSTR ) SELECT COUNT(1) AS COUNT_INFO FROM ( SELECT A.SBJCT_ID FROM TB_LMS_SBJCT A JOIN TB_SYS_JOB_SCH_T B ON A.SBJCT_ID = B.DGRS_YR AND A.CRS_ID = B.DGRS_SMSTR WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.SBJCT_ID = #{year} AND A.CRS_ID = #{semester}
AND A.CRS_ID = #{courseCode}
AND A.DVCLAS_NO = #{section}
AND A.SBJCT_ID = #{crsCreCd}
) A JOIN SBJCT_PROF B ON A.SBJCT_ID = B.SBJCT_ID AND B.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT') AND B.USER_ID = #{userId} JOIN TB_LMS_EXAM_CRE_CRS_RLTN C ON A.SBJCT_ID = C.SBJCT_ID JOIN TB_LMS_EXAM_BSC D ON C.EXAM_ID = D.EXAM_ID AND D.DELYN = 'N' AND D.EXAM_CTGRCD = 'EXAM' AND D.EXAM_TYCD = 'EXAM' AND D.TKEXAM_TYCD IN ('M', 'L') JOIN TB_LMS_EXAM_ABSNCE E ON A.SBJCT_ID = E.SBJCT_ID AND D.EXAM_ID = E.EXAM_ID AND E.APRV_STSCD IN ('APPLICATE', 'RAPPLICATE') AND E.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S' AND AUDITYN = 'N')

/* SQL ID : ApiDAO.selectProfScoreObjtRequestCountInfo 설 명 : 재확인 신청 받은 건수 TB_SYS_JOB_SCH_T : 성적재확인신청기간, 성적재확인신청정정기간에 해당되는 일자조회 */ WITH TB_SYS_JOB_SCH_T AS ( SELECT TSJS.SYSJOB_SCHDL_SYMD , TSJS.SYSJOB_SCHDL_EYMD , (CASE WHEN TSJS.SYSJOB_SCHDL_TYCD = '00210202' AND TSC.CD_OPTN = '1' THEN 'C' WHEN TSJS.SYSJOB_SCHDL_TYCD = '00210204' AND TSC.CD_OPTN = '2' THEN 'G' WHEN TSJS.SYSJOB_SCHDL_TYCD = '00210203' AND TSC.CD_OPTN = '1' THEN 'C' END) AS UNIV_CD FROM TB_LMS_SYSJOB_SCHDL TSJS LEFT JOIN TB_SYS_CODE TSC ON TSJS.SYSJOB_SCHDL_TYCD = TSC.CD WHERE TSJS.SYSJOB_SCHDL_TYCD IN ( '00210202', '00210204', '00210203')
AND TSJS.DGRS_YR = #{year}
AND TSJS.DGRS_YR = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TSJS.DGRS_SMSTR = #{semester}
AND TSJS.DGRS_SMSTR = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TSJS.ORG_ID = #{orgId} AND TSJS.USEYN = 'Y' ) SELECT IFNULL(COUNT(DISTINCT TLSSO.MRK_OBJCT_APLY_ID), 0) AS COUNT_INFO FROM TB_LMS_SBJCT TLCC , SBJCT_PROF TLCCTR , MRK_OBJCT_APLY TLSSO , TB_SYS_JOB_SCH_T JOB WHERE TLCC.SBJCT_ID = TLCCTR.SBJCT_ID AND TLCC.SBJCT_ID = TLSSO.SBJCT_ID AND TLCC.DELYN = 'N' AND TLCC.USEYN = 'Y' AND TLCCTR.USER_ID = #{userId} AND TLCCTR.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT')
AND TLCC.SBJCT_ID = #{year}
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND JOB.UNIV_CD = TLCC.UNIV_CD AND TLSSO.CHG_PROC_CD IS NULL
AND TLCC.CRS_ID = #{courseCode}
AND TLCC.DVCLAS_NO = #{section}
AND TLCC.SBJCT_ID = #{crsCreCd}
AND (DATE_FORMAT(NOW(), "%Y-%m-%d %T") BETWEEN DATE_FORMAT(JOB.SYSJOB_SCHDL_SYMD, "%Y-%m-%d %T") AND DATE_FORMAT(ADDDATE(JOB.SYSJOB_SCHDL_EYMD, INTERVAL 1 DAY), "%Y-%m-%d %T") )

/* SQL ID : ApiDAO.selectDisabledPersonRequestCountInfo 설 명 : 장애인지원신청 건수 */ WITH TB_SYS_JOB_SCH_T AS ( SELECT TSJS.SYSJOB_SCHDL_SYMD , TSJS.SYSJOB_SCHDL_EYMD , TSJS.DGRS_YR , TSJS.DGRS_SMSTR FROM TB_LMS_SYSJOB_SCHDL TSJS WHERE TSJS.SYSJOB_SCHDL_TYCD IN ( '00190809' )
AND TSJS.DGRS_YR = #{year}
AND TSJS.DGRS_YR = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TSJS.DGRS_SMSTR = #{semester}
AND TSJS.DGRS_SMSTR = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TSJS.ORG_ID = #{orgId} AND TSJS.USEYN = 'Y' AND ( DATE_FORMAT(NOW(), "%Y-%m-%d %T") BETWEEN DATE_FORMAT(TSJS.SYSJOB_SCHDL_SYMD, "%Y-%m-%d %T") AND DATE_FORMAT(ADDDATE(TSJS.SYSJOB_SCHDL_EYMD, INTERVAL 1 DAY), "%Y-%m-%d %T") ) ) SELECT IFNULL(COUNT(1), 0) AS COUNT_INFO FROM TB_LMS_SBJCT TLCC INNER JOIN SBJCT_PROF TLCCTR ON TLCC.SBJCT_ID = TLCCTR.SBJCT_ID AND TLCC.DELYN = 'N' AND TLCC.USEYN = 'Y' AND TLCCTR.USER_ID = #{userId} AND TLCCTR.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT') INNER JOIN TB_SYS_JOB_SCH_T TSJST ON TSJST.DGRS_YR = TLCC.SBJCT_ID AND TSJST.DGRS_SMSTR = TLCC.CRS_ID
AND TLCC.SBJCT_ID = #{year}
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{courseCode}
AND TLCC.DVCLAS_NO = #{section}
AND TLCC.SBJCT_ID = #{crsCreCd}
INNER JOIN TB_LMS_ATNDLC_SBJCT TLS ON TLCC.SBJCT_ID = TLS.SBJCT_ID AND TLS.ATNDLC_STSCD = 'S' /* 승인상태 */ AND TLS.AUDITYN = 'N' /* 청강생여부 */ AND TLS.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND TLS.ORG_ID = #{orgId} INNER JOIN TB_LMS_USR THUI ON TLS.USER_ID = THUI.USER_ID AND THUI.DISABLILITY_YN = 'Y' AND THUI.EXAM_SPRT_APLY_TYCD = 'Y' LEFT JOIN TB_LMS_EXAM_SPRT_APLY TLED ON TLS.STD_ID = TLED.STD_ID AND TLED.EXAM_SPRT_APLY_ID IS NULL

/* SQL ID : ApiDAO.selectAllNoticeList 설 명 : 강의실 전체 공지사항 내역 */ SELECT A.ATCL_TTL , A.RGTRNM , DATE_FORMAT(A.FRST_INQ_DTTM,'%Y-%m-%d') AS FRST_INQ_DTTM
/* , CONCAT('/bbs/bbsHome/Form/atclView.do&#63;bbsId=', A.BBS_ID, '&amp;atclId=', A.ATCL_ID) AS VIEW_LINK */ /* , CONCAT('/sso/CreateRequest.jsp&#63;RelayState=https&#58;&#47;&#47;devlms.hycu.ac.kr/bbs/bbsHome/Form/atclView.do&#63;bbsId=', A.BBS_ID, '&atclId=', A.ATCL_ID) AS VIEW_LINK */ , CONCAT('/common/moveNotice.do&#63;goUrl=/bbs/bbsHome/Form/atclView.do&subParam=bbsId=', A.BBS_ID, '@atclId=', A.ATCL_ID) AS VIEW_LINK
FROM TB_LMS_BBS_ATCL A WHERE A.BBS_ID = #{bbsId} AND A.DELYN = 'N' AND A.LOCKYN = 'N' AND ( A.RSRV_USEYN = 'N' OR A.RSRV_DTTM <= FN_DTTM() )
AND A.UNIV_CD IN (#{uniCd}, 'P')
AND A.UNIV_GBNCD IN (#{univGbn}, '0')
ORDER BY A.FRST_INQ_DTTM DESC LIMIT 5

/* SQL ID : ApiDAO.selectStuLessonNoticeList 설 명 : 학생별 강의 공지사항 내역 */ SELECT A.ATCL_TTL , A.RGTRNM , DATE_FORMAT(A.FRST_INQ_DTTM,'%Y-%m-%d') AS FRST_INQ_DTTM
, CASE WHEN BBS_ID = 'TEAM' THEN CONCAT('/common/moveCrs.do&#63;goUrl=/bbs/bbsLect/Form/atclView.do&subParam=bbsCd=TEAM@crsCreCd=', D.SBJCT_ID, '@bbsId=', A.BBS_ID, '@atclId=', A.ATCL_ID) ELSE CONCAT('/common/moveCrs.do&#63;goUrl=/bbs/bbsLect/Form/atclView.do&subParam=crsCreCd=', D.SBJCT_ID, '@bbsId=', A.BBS_ID, '@atclId=', A.ATCL_ID) END AS VIEW_LINK
FROM TB_LMS_BBS_ATCL A , TB_LMS_BBS B , TB_HOME_BBS_RLTN C , ( SELECT DISTINCT TLCC.SBJCT_ID FROM TB_LMS_SBJCT TLCC , TB_LMS_ATNDLC_SBJCT TLS , TB_LMS_TERM_CRE_CRS_RLTN TLTCCR , CRS_SMSTR TLT WHERE TLCC.SBJCT_ID = TLS.SBJCT_ID AND TLCC.SBJCT_ID = TLTCCR.SBJCT_ID AND TLTCCR.CRS_SMSTR_ID = TLT.CRS_SMSTR_ID AND TLT.OP_SDTTM <= FN_DTTM() AND TLCC.DELYN = 'N' AND TLCC.USEYN = 'Y' AND TLS.ATNDLC_STSCD = 'S' /* 승인상태 */ AND TLS.AUDITYN = 'N' /* 청강생여부 */ AND TLS.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND TLS.ORG_ID = #{orgId} AND TLS.USER_ID = #{userId}
AND TLCC.SBJCT_ID = #{year}
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{courseCode}
AND TLCC.SBJCT_ID = #{crsCreCd}
AND TLCC.DVCLAS_NO = #{section}
) D WHERE A.BBS_ID = B.BBS_ID AND B.BBS_ID = #{alarmType} AND B.BBS_ID = C.BBS_ID AND D.SBJCT_ID = C.RLTN_REF_CD AND C.CONTS_TYCD = 'COURSE' AND B.DELYN = 'N' AND B.USEYN = 'Y' AND B.SYS_BSC_PVSNYN = 'Y' AND B.ORG_ID = #{orgId} AND A.DELYN = 'N' AND A.UP_ATCL_ID IS NULL AND ( A.LOCKYN = 'N' OR A.RGTR_ID = #{userId} ) AND ( A.RSRV_USEYN = 'N' OR A.RSRV_DTTM <= FN_DTTM() ) ORDER BY A.FRST_INQ_DTTM DESC LIMIT 5

/* SQL ID : ApiDAO.selectProfLessonNoticeList 설 명 : 교수,조교 강의 공지사항 내역 */ SELECT A.ATCL_TTL , A.RGTRNM , DATE_FORMAT(A.FRST_INQ_DTTM,'%Y-%m-%d') AS FRST_INQ_DTTM
, CONCAT('/common/moveCrs.do&#63;goUrl=/bbs/bbsLect/Form/atclView.do&subParam=bbsCd=ALARM@menuType=PROFESSOR@crsCreCd=', D.SBJCT_ID, '@bbsId=', A.BBS_ID, '@atclId=', A.ATCL_ID) as VIEW_LINK
FROM TB_LMS_BBS_ATCL A , TB_LMS_BBS B , TB_HOME_BBS_RLTN C , ( SELECT DISTINCT TLCC.SBJCT_ID FROM TB_LMS_SBJCT TLCC , SBJCT_PROF TLCCTR , TB_LMS_TERM_CRE_CRS_RLTN TLTCCR WHERE TLCC.SBJCT_ID = TLCCTR.SBJCT_ID AND TLCC.SBJCT_ID = TLTCCR.SBJCT_ID AND TLCC.DELYN = 'N' AND TLCC.USEYN = 'Y' AND TLCCTR.USER_ID = #{userId} AND TLCCTR.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT')
AND TLCC.SBJCT_ID = #{year}
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{courseCode}
AND TLCC.SBJCT_ID = #{crsCreCd}
AND TLCC.DVCLAS_NO = #{section}
) D WHERE A.BBS_ID = B.BBS_ID AND B.BBS_ID = #{alarmType} AND B.BBS_ID = C.BBS_ID AND D.SBJCT_ID = C.RLTN_REF_CD AND C.CONTS_TYCD = 'COURSE' AND B.DELYN = 'N' AND B.USEYN = 'Y' AND B.SYS_BSC_PVSNYN = 'Y' AND B.ORG_ID = #{orgId} AND A.DELYN = 'N' AND A.UP_ATCL_ID IS NULL ORDER BY A.FRST_INQ_DTTM DESC LIMIT 5

/* SQL ID : ApiDAO.selectStuLessonQnaList 설 명 : 학생 과목 QNA 내역 */ SELECT THBA.ATCL_TTL , CONCAT(THBA.RGTRNM, ' (', THBA.RGTR_ID, ')') AS RGTRNM , DATE_FORMAT(THBA.FRST_INQ_DTTM, '%Y-%m-%d') AS FRST_INQ_DTTM , IF(EXISTS (SELECT 1 FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = THBA.ATCL_ID AND DELYN = 'N'), 'Y', 'N') AS ANSWER_YN
, CASE WHEN THBR.CONTS_TYCD = 'TEAM' THEN CONCAT('/common/moveCrs.do&#63;goUrl=/bbs/bbsLect/Form/atclView.do&subParam=bbsCd=TEAM@crsCreCd=', TLCC.SBJCT_ID, '@bbsId=', THBA.BBS_ID, '@atclId=', THBA.ATCL_ID) ELSE CONCAT('/common/moveCrs.do&#63;goUrl=/bbs/bbsLect/Form/atclView.do&subParam=crsCreCd=', TLCC.SBJCT_ID, '@bbsId=', THBA.BBS_ID, '@atclId=', THBA.ATCL_ID) END AS VIEW_LINK
FROM TB_LMS_SBJCT TLCC INNER JOIN TB_LMS_ATNDLC_SBJCT TLS ON TLCC.SBJCT_ID = TLS.SBJCT_ID AND TLCC.DELYN = 'N' AND TLCC.USEYN = 'Y' AND TLS.ATNDLC_STSCD = 'S' /* 승인상태 */ AND TLS.AUDITYN = 'N' /* 청강생여부 */ AND TLS.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND TLS.USER_ID = #{userId} AND TLS.ORG_ID = #{orgId}
AND TLCC.SBJCT_ID = #{year}
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{courseCode}
AND TLCC.SBJCT_ID = #{crsCreCd}
AND TLCC.DVCLAS_NO = #{section}
INNER JOIN TB_HOME_BBS_RLTN THBR ON THBR.RLTN_REF_CD = TLCC.SBJCT_ID AND THBR.CONTS_TYCD = 'COURSE' JOIN TB_LMS_BBS THBI ON THBI.BBS_ID = THBR.BBS_ID AND THBI.DELYN = 'N' AND THBI.USEYN = 'Y' AND THBI.SYS_BSC_PVSNYN = 'Y' AND THBI.BBS_ID IN ('QNA', 'SECRET') AND THBI.ORG_ID = #{orgId} INNER JOIN TB_LMS_BBS_ATCL THBA ON THBA.BBS_ID = THBR.BBS_ID AND THBA.DELYN = 'N' AND THBA.UP_ATCL_ID IS NULL AND THBA.RGTR_ID = TLS.USER_ID ORDER BY THBA.FRST_INQ_DTTM DESC LIMIT 5

/* SQL ID : ApiDAO.selectProfLessonQnaList 설 명 : 교수,조교 과목 QNA 내역 */ SELECT THBA.ATCL_TTL , CONCAT(THBA.RGTRNM, ' (', THBA.RGTR_ID, ')') AS ENQUIRER , DATE_FORMAT(THBA.FRST_INQ_DTTM, '%Y-%m-%d') AS FRST_INQ_DTTM , IF(EXISTS (SELECT 1 FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = THBA.ATCL_ID AND DELYN = 'N'), 'Y', 'N') AS ANSWER_YN
, CONCAT('/common/moveCrs.do&#63;goUrl=/bbs/bbsLect/Form/atclView.do&subParam=bbsCd=ALARM@menuType=PROFESSOR@crsCreCd=', TLCC.SBJCT_ID, '@bbsId=', THBA.BBS_ID, '@atclId=', THBA.ATCL_ID) AS VIEW_LINK
FROM TB_LMS_SBJCT TLCC INNER JOIN SBJCT_PROF TLCCTR ON TLCC.SBJCT_ID = TLCCTR.SBJCT_ID AND TLCC.DELYN = 'N' AND TLCC.USEYN = 'Y' AND TLCCTR.USER_ID = #{userId} AND TLCCTR.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT')
AND TLCC.SBJCT_ID = #{year}
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{courseCode}
AND TLCC.SBJCT_ID = #{crsCreCd}
AND TLCC.DVCLAS_NO = #{section}
INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN TLTCCR ON TLCC.SBJCT_ID = TLTCCR.SBJCT_ID INNER JOIN TB_HOME_BBS_RLTN THBR ON THBR.RLTN_REF_CD = TLCC.SBJCT_ID AND THBR.CONTS_TYCD = 'COURSE' JOIN TB_LMS_BBS THBI ON THBI.BBS_ID = THBR.BBS_ID AND THBI.DELYN = 'N' AND THBI.USEYN = 'Y' AND THBI.SYS_BSC_PVSNYN = 'Y' AND THBI.BBS_ID IN ('QNA', 'SECRET') AND THBI.ORG_ID = #{orgId} INNER JOIN TB_LMS_BBS_ATCL THBA ON THBA.BBS_ID = THBR.BBS_ID AND THBA.DELYN = 'N' AND THBA.UP_ATCL_ID IS NULL ORDER BY THBA.FRST_INQ_DTTM DESC LIMIT 5

/* SQL ID : ApiDAO.selectStaffLessonQnaList 설 명 : 직원 과목 QNA 내역 */ SELECT THBA.ATCL_TTL , CONCAT(THBA.RGTRNM, ' (', THBA.RGTR_ID, ')') AS ENQUIRER , DATE_FORMAT(THBA.FRST_INQ_DTTM, '%Y-%m-%d') AS FRST_INQ_DTTM , IF(EXISTS (SELECT 1 FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = THBA.ATCL_ID AND DELYN = 'N'), 'Y', 'N') AS ANSWER_YN
, CONCAT('/common/moveCrs.do&#63;goUrl=/bbs/bbsLect/Form/atclView.do&subParam=bbsCd=ALARM@menuType=PROFESSOR@crsCreCd=', TLCC.SBJCT_ID, '@bbsId=', THBA.BBS_ID, '@atclId=', THBA.ATCL_ID) AS VIEW_LINK
FROM TB_LMS_SBJCT TLCC INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN TLTCCR ON TLCC.SBJCT_ID = TLTCCR.SBJCT_ID AND TLCC.DELYN = 'N' AND TLCC.USEYN = 'Y'
AND TLCC.SBJCT_ID = #{year}
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{courseCode}
AND TLCC.SBJCT_ID = #{crsCreCd}
AND TLCC.DVCLAS_NO = #{section}
INNER JOIN TB_HOME_BBS_RLTN THBR ON THBR.RLTN_REF_CD = TLCC.SBJCT_ID AND THBR.CONTS_TYCD = 'COURSE' JOIN TB_LMS_BBS THBI ON THBI.BBS_ID = THBR.BBS_ID AND THBI.DELYN = 'N' AND THBI.USEYN = 'Y' AND THBI.SYS_BSC_PVSNYN = 'Y' AND THBI.BBS_ID IN ('QNA', 'SECRET') AND THBI.ORG_ID = #{orgId} INNER JOIN TB_LMS_BBS_ATCL THBA ON THBA.BBS_ID = THBR.BBS_ID AND THBA.DELYN = 'N' AND THBA.UP_ATCL_ID IS NULL ORDER BY THBA.FRST_INQ_DTTM DESC LIMIT 5

/* SQL ID : ApiDAO.selectRealSeminarList 설 명 : 실시간 세미나 내역 */ SELECT A.SMNR_ID , A.SEMINAR_NM , CONCAT(A.SMNR_MNTS, ' 분') AS SMNR_MNTS , A.SMNR_SDTTM , A.SMNR_EDTTM , A.VIEW_LINK FROM (SELECT A.SMNR_ID , A.SBJCT_ID , A.SEMINAR_NM , A.SMNR_MNTS
, DATE_FORMAT(STR_TO_DATE(A.SMNR_SDTTM, '%Y%m%d%H%i%s'),'%Y.%m.%d %H:%i') AS SMNR_SDTTM , DATE_FORMAT(STR_TO_DATE(A.SMNR_EDTTM, '%Y%m%d%H%i%s'),'%Y.%m.%d %H:%i') AS SMNR_EDTTM
, CONCAT('/seminar/seminarHome/seminarAttendManage.do&#63;crsCreCd=', A.SBJCT_ID, '&seminarId=', A.SMNR_ID) AS VIEW_LINK
, A.FRST_INQ_DTTM FROM TB_LMS_SMNR A INNER JOIN TB_LMS_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' AND B.USEYN = 'Y' AND B.SBJCT_TYCD = 'UNI'
AND B.SBJCT_ID = #{year}
AND B.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND B.CRS_ID = #{semester}
AND B.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND B.CRS_ID = #{courseCode}
AND B.SBJCT_ID = #{crsCreCd}
AND B.DVCLAS_NO = #{section}
INNER JOIN SBJCT_PROF C ON A.SBJCT_ID = C.SBJCT_ID
AND C.USER_ID = #{userId}
AND C.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT') INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN D ON B.SBJCT_ID = D.SBJCT_ID INNER JOIN CRS_SMSTR E ON D.CRS_SMSTR_ID = E.CRS_SMSTR_ID AND E.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND (DATE_FORMAT(NOW(), "%Y-%m-%d %T") <= DATE_FORMAT(A.SMNR_SDTTM, "%Y-%m-%d %T") OR DATE_FORMAT(NOW(), "%Y-%m-%d %T") BETWEEN DATE_FORMAT(A.SMNR_SDTTM, "%Y-%m-%d %T") AND DATE_FORMAT(ADDDATE(A.SMNR_EDTTM, INTERVAL 1 DAY), "%Y-%m-%d %T") ) UNION SELECT A.SMNR_ID , A.SBJCT_ID , A.SEMINAR_NM , A.SMNR_MNTS
, DATE_FORMAT(STR_TO_DATE(A.SMNR_SDTTM, '%Y%m%d%H%i%s'),'%Y.%m.%d %H:%i') AS SMNR_SDTTM , DATE_FORMAT(STR_TO_DATE(A.SMNR_EDTTM, '%Y%m%d%H%i%s'),'%Y.%m.%d %H:%i') AS SMNR_EDTTM
, CONCAT('/seminar/seminarHome/stuSeminarView.do&#63;seminarId=', A.SMNR_ID, '&stdNo=', C.STD_ID) AS VIEW_LINK
, A.FRST_INQ_DTTM FROM TB_LMS_SMNR A INNER JOIN TB_LMS_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' AND B.USEYN = 'Y' AND B.SBJCT_TYCD = 'UNI'
AND B.SBJCT_ID = #{year}
AND B.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND B.CRS_ID = #{semester}
AND B.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND B.CRS_ID = #{courseCode}
AND B.SBJCT_ID = #{crsCreCd}
AND B.DVCLAS_NO = #{section}
INNER JOIN TB_LMS_ATNDLC_SBJCT C ON A.SBJCT_ID = C.SBJCT_ID AND C.ATNDLC_STSCD = 'S' AND C.AUDITYN = 'N' AND C.ORG_ID = #{orgId}
AND C.USER_ID = #{userId}
INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN D ON B.SBJCT_ID = D.SBJCT_ID INNER JOIN CRS_SMSTR E ON D.CRS_SMSTR_ID = E.CRS_SMSTR_ID AND E.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND (DATE_FORMAT(NOW(), "%Y-%m-%d %T") <= DATE_FORMAT(A.SMNR_SDTTM, "%Y-%m-%d %T") OR DATE_FORMAT(NOW(), "%Y-%m-%d %T") BETWEEN DATE_FORMAT(A.SMNR_SDTTM, "%Y-%m-%d %T") AND DATE_FORMAT(ADDDATE(A.SMNR_EDTTM, INTERVAL 1 DAY), "%Y-%m-%d %T") ) ) A ORDER BY A.SMNR_SDTTM LIMIT 2

/* SQL ID : ApiDAO.selectStdAvgAllProgressRatio 설 명 : 학생 학습 나의 평균 */ WITH CRS_STD_INFO AS ( SELECT A.SBJCT_ID , B.STD_ID , B.USER_ID FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' AND B.USER_ID = #{userId} AND B.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND A.SBJCT_TYCD = 'UNI' AND A.CRS_ID NOT LIKE '%JLPT%'
AND A.SBJCT_ID = #{year}
AND A.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND A.CRS_ID = #{semester}
AND A.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND A.CRS_ID = #{courseCode}
AND A.SBJCT_ID = #{crsCreCd}
AND A.DVCLAS_NO = #{section}
) SELECT IFNULL(SUM(IF(C.ATNDLC_STSCD IN ('COMPLETE', 'LATE'), 1, 0)), 0) / COUNT(B.LCTR_SCHDL_ID) * 100 AS STD_PROG_RATIO FROM CRS_STD_INFO A JOIN TB_LMS_SBJCT_LCTR_SCHDL B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' AND ( B.LCTR_WKNO_GBNCD IN('02', '03') OR EXISTS ( SELECT 1 FROM TB_LMS_SBJCT_LCTR_CONTS AA WHERE AA.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID AND (AA.LCTR_CONTS_GBNCD = 'VIDEO' OR (AA.LCTR_CONTS_GBNCD = 'VIDEO_LINK' AND EXISTS (SELECT 1 FROM SBJCT_LCTR_CONTS_PAGE WHERE SBJCT_LCTR_CONTS_ID = AA.SBJCT_LCTR_CONTS_ID))) AND AA.DELYN = 'N' AND AA.PRG_RFLTYN = 'Y' ) ) AND DATE_FORMAT(NOW(), '%Y%m%d') >= IFNULL(B.LCTR_RCG_SYMD, B.LCTR_SYMD) LEFT JOIN TB_LMS_LESSON_STUDY_STATE C ON A.STD_ID = C.STD_ID AND B.LCTR_SCHDL_ID = C.LCTR_SCHDL_ID

/* SQL ID : ApiDAO.selectStdDetailProgressRatio 설 명 : 수강과목 내역 및 과목별 진도율 */ SELECT CONCAT(TLP.SBJCTNM, ' (', TLP.DVCLAS_NO, '반)') AS SBJCTNM , TLP.DVCLAS_NO , TLP.LRN_WKNO , TLP.TOT_WEEK_CNT , CASE WHEN TLP.PRGRT = '100' THEN TLP.PRGRT WHEN TLP.PRGRT != '100' THEN CASE WHEN TLP.PRGRT = '0' THEN TLP.PRGRT WHEN TLP.PRGRT != '0' THEN IFNULL(FORMAT(TLP.PRGRT, 2), 0) END END PRGRT , TLP.LCTRRM_URL , TLP.USER_ID FROM TB_LMS_LRN_PRGRT TLP INNER JOIN TB_LMS_SBJCT TLCC ON TLP.SBJCT_ID = TLCC.SBJCT_ID AND TLCC.USEYN = 'Y' AND TLCC.DELYN = 'N' INNER JOIN TB_LMS_ATNDLC_SBJCT TLS ON TLCC.SBJCT_ID = TLS.SBJCT_ID AND TLP.USER_ID = TLS.USER_ID AND TLS.ATNDLC_STSCD = 'S' /* 승인상태 */ AND TLS.AUDITYN = 'N' /* 청강생여부 */ AND TLS.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND TLS.ORG_ID = #{orgId} WHERE 1 = 1
AND TLP.SBJCT_ID = #{year}
AND TLP.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLP.CRS_ID = #{semester}
AND TLP.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLP.SBJCT_ID = #{crsCreCd}
AND TLP.DVCLAS_NO = #{section}
AND TLP.USER_ID = #{userId}
ORDER BY TLP.SBJCTNM, TLP.DVCLAS_NO

/* SQL ID : ApiDAO.selectCollDetailProgressRatio 설 명 : 수강과목 내역 및 과목별 진도율 */ SELECT CONCAT(TLP.SBJCTNM, ' (', TLP.DVCLAS_NO, '반) ') AS SBJCTNM , TLP.DVCLAS_NO , TLP.LRN_WKNO , TLP.TOT_WEEK_CNT , CASE WHEN TLP.PRGRT = '100' THEN TLP.PRGRT WHEN TLP.PRGRT != '100' THEN CASE WHEN TLP.PRGRT = '0' THEN TLP.PRGRT WHEN TLP.PRGRT != '0' THEN IFNULL(FORMAT(TLP.PRGRT, 2), 0) END END PRGRT , TLP.LCTRRM_URL , TLP.USER_ID FROM TB_LMS_LRN_PRGRT TLP INNER JOIN TB_LMS_SBJCT TLCC ON TLP.SBJCT_ID = TLCC.SBJCT_ID AND TLCC.USEYN = 'Y' AND TLCC.DELYN = 'N' INNER JOIN TB_LMS_ATNDLC_SBJCT TLS ON TLCC.SBJCT_ID = TLS.SBJCT_ID AND TLP.USER_ID = TLS.USER_ID AND TLS.ATNDLC_STSCD = 'S' /* 승인상태 */ AND TLS.AUDITYN = 'N' /* 청강생여부 */ AND TLS.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND TLS.ORG_ID = #{orgId} AND TLP.UNIV_CD = 'C' WHERE 1 = 1
AND TLP.SBJCT_ID = #{year}
AND TLP.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLP.CRS_ID = #{semester}
AND TLP.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLP.SBJCT_ID = #{crsCreCd}
AND TLP.DVCLAS_NO = #{section}
AND TLP.USER_ID = #{userId}

/* SQL ID : ApiDAO.selectGridDetailProgressRatio 설 명 : 수강과목 내역 및 과목별 진도율 */ SELECT CONCAT(TLP.SBJCTNM, ' (', TLP.DVCLAS_NO, '반) ') AS SBJCTNM , TLP.DVCLAS_NO , TLP.LRN_WKNO , TLP.TOT_WEEK_CNT , CASE WHEN TLP.PRGRT = '100' THEN TLP.PRGRT WHEN TLP.PRGRT != '100' THEN CASE WHEN TLP.PRGRT = '0' THEN TLP.PRGRT WHEN TLP.PRGRT != '0' THEN IFNULL(FORMAT(TLP.PRGRT, 2), 0) END END PRGRT , TLP.LCTRRM_URL , TLP.USER_ID FROM TB_LMS_LRN_PRGRT TLP INNER JOIN TB_LMS_SBJCT TLCC ON TLP.SBJCT_ID = TLCC.SBJCT_ID AND TLCC.USEYN = 'Y' AND TLCC.DELYN = 'N' INNER JOIN TB_LMS_ATNDLC_SBJCT TLS ON TLCC.SBJCT_ID = TLS.SBJCT_ID AND TLP.USER_ID = TLS.USER_ID AND TLS.ATNDLC_STSCD = 'S' /* 승인상태 */ AND TLS.AUDITYN = 'N' /* 청강생여부 */ AND TLS.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND TLS.ORG_ID = #{orgId} AND TLP.UNIV_CD = 'G' WHERE 1 = 1
AND TLP.SBJCT_ID = #{year}
AND TLP.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLP.CRS_ID = #{semester}
AND TLP.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLP.SBJCT_ID = #{crsCreCd}
AND TLP.DVCLAS_NO = #{section}
AND TLP.USER_ID = #{userId}

/* SQL ID : ApiDAO.selectProfAvgProgressRatio 설 명 : 교수 학습 평균 진도율 조회 */ WITH PROF_COURSE_T AS ( SELECT A.SBJCT_ID , A.SBJCTNM , A.SBJCT_ID , A.CRS_ID , A.DVCLAS_NO , A.UNIV_CD FROM TB_LMS_SBJCT A JOIN SBJCT_PROF B ON A.SBJCT_ID = B.SBJCT_ID AND B.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT') AND B.USER_ID = #{userId} WHERE A.DELYN = 'N' AND A.SBJCT_TYCD = 'UNI' AND A.CRS_ID NOT LIKE '%JLPT%'
AND A.SBJCT_ID = #{year}
AND A.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND A.CRS_ID = #{semester}
AND A.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND A.CRS_ID = #{courseCode}
AND A.DVCLAS_NO = #{section}
) SELECT IFNULL(ROUND(STUDY_SCHEDULE_CNT * 100 / ALL_SCHEDULE_CNT, 2), 0) AS PROF_PROG_RATIO -- 교수별 평균 진도율 FROM ( SELECT COUNT(B.LCTR_SCHDL_ID) AS ALL_SCHEDULE_CNT , COUNT(C.STD_ID) AS STUDY_SCHEDULE_CNT FROM ( SELECT A.SBJCT_ID , B.STD_ID , B.AUDITYN , C.USER_ID , C.USERNM , C.ENTR_YY , C.DEPTNM , C.MOBILE_NO , C.EMAIL FROM PROF_COURSE_T A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N' AND B.ORG_ID = #{orgId} JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID ) A JOIN ( SELECT A.SBJCT_ID , B.LCTR_SCHDL_ID FROM PROF_COURSE_T A JOIN TB_LMS_SBJCT_LCTR_SCHDL B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' AND ( B.LCTR_WKNO_GBNCD IN ('02', '03') -- 세미나 주차 포함 OR EXISTS ( SELECT 1 FROM TB_LMS_SBJCT_LCTR_CONTS AA WHERE AA.LCTR_SCHDL_ID = B.LCTR_SCHDL_ID AND ( AA.LCTR_CONTS_GBNCD = 'VIDEO' OR ( AA.LCTR_CONTS_GBNCD = 'VIDEO_LINK' AND EXISTS (SELECT 1 FROM SBJCT_LCTR_CONTS_PAGE WHERE SBJCT_LCTR_CONTS_ID = AA.SBJCT_LCTR_CONTS_ID) ) ) AND AA.DELYN = 'N' AND AA.PRG_RFLTYN = 'Y' ) ) AND FN_DTTM() >= IFNULL(B.LCTR_RCG_SYMD, B.LCTR_SYMD) ) B ON A.SBJCT_ID = B.SBJCT_ID LEFT JOIN TB_LMS_LESSON_STUDY_STATE C ON A.STD_ID = C.STD_ID AND B.LCTR_SCHDL_ID = C.LCTR_SCHDL_ID AND C.ATNDLC_STSCD IN ('COMPLETE', 'LATE') ) A

/* SQL ID : ApiDAO.selectProfSubjectProgressRatio 설 명 : 교수 과목별 진도율 조회 */ WITH CRS_STD_INFO AS ( SELECT TLCC.SBJCT_ID , TLCC.SBJCTNM , TLCC.SBJCT_ID , TLCC.CRS_ID , TLCC.DVCLAS_NO , TLCC.UNIV_CD , STD.STD_ID , STD.USER_ID FROM TB_LMS_SBJCT TLCC INNER JOIN SBJCT_PROF TLCCTR ON TLCC.SBJCT_ID = TLCCTR.SBJCT_ID AND TLCCTR.USER_ID = #{userId} AND TLCCTR.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT') LEFT JOIN ( SELECT SBJCT_ID , TLS.STD_ID , TLS.USER_ID FROM TB_LMS_ATNDLC_SBJCT TLS INNER JOIN TB_LMS_USER_ACNT THUL ON TLS.USER_ID = THUL.USER_ID AND THUL.ACNT_STSCD = 'U' AND TLS.ATNDLC_STSCD = 'S' /* 승인상태 */ AND TLS.AUDITYN = 'N' /* 청강생여부 */ AND TLS.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND TLS.ORG_ID = #{orgId} ) STD ON TLCC.SBJCT_ID = STD.SBJCT_ID AND TLCC.DELYN = 'N' WHERE 1 = 1
AND TLCC.SBJCT_ID = #{year}
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{courseCode}
AND TLCC.DVCLAS_NO = #{section}
) SELECT X.SBJCT_ID , CONCAT(X.SBJCTNM, ' (', X.DVCLAS_NO, '반) ') AS SBJCTNM , X.DVCLAS_NO , IFNULL(FORMAT((SELECT SUM(IFNULL(PRGRT, 0)) FROM TB_LMS_LRN_PRGRT WHERE SBJCT_ID = X.SBJCT_ID) / IFNULL((SELECT COUNT(USER_ID) FROM CRS_STD_INFO WHERE SBJCT_ID = X.SBJCT_ID), 0), 2), 0) AS CRS_PROG_RATIO , CONCAT('/crs/crsHomeProf.do?crsCreCd=', X.SBJCT_ID) AS LCTRRM_URL FROM ( SELECT CSI.SBJCT_ID , CSI.SBJCTNM , CSI.DVCLAS_NO FROM CRS_STD_INFO CSI LEFT JOIN TB_LMS_LRN_PRGRT TLP ON CSI.SBJCT_ID = TLP.SBJCT_ID AND CSI.USER_ID = TLP.USER_ID GROUP BY CSI.SBJCT_ID , CSI.SBJCTNM , CSI.DVCLAS_NO ORDER BY CSI.SBJCTNM ) X

/* SQL ID : ApiDAO.selectProfDepartPerWeekAttend 설 명 : 교수 학과별 주차별 출석현황 조회 */ WITH STD_INFO AS ( SELECT TLCC.SBJCT_ID , TLCC.DEPT_CD , TLCC.SBJCT_ID , TLS.STD_ID , TLS.USER_ID FROM TB_LMS_SBJCT TLCC INNER JOIN SBJCT_PROF TLCCTR ON TLCC.SBJCT_ID = TLCCTR.SBJCT_ID AND TLCCTR.USER_ID = #{userId} AND TLCCTR.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT') INNER JOIN TB_LMS_ATNDLC_SBJCT TLS ON TLCC.SBJCT_ID = TLS.SBJCT_ID INNER JOIN TB_LMS_USER_ACNT THUL ON TLS.USER_ID = THUL.USER_ID AND THUL.ACNT_STSCD = 'U' AND TLS.ATNDLC_STSCD = 'S' /* 승인상태 */ AND TLS.AUDITYN = 'N' /* 청강생여부 */ AND TLS.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND TLS.ORG_ID = #{orgId} WHERE 1 = 1 AND TLCC.DEPT_CD = (SELECT DEPT_CD FROM TB_LMS_USR WHERE USER_ID = #{userId})
AND TLCC.SBJCT_ID IN (#{lastYear}, #{year})
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
), LESSON_SCHEDULE AS ( SELECT SCH.* FROM ( SELECT DISTINCT TLLS.SBJCT_ID , TLCC.SBJCTNM , TLCC.DEPT_CD , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD THUDC WHERE THUDC.DEPT_CD = TLCC.DEPT_CD) AS DEPTNM , TLCC.SBJCT_ID , TLLS.LCTR_SCHDL_ID , TLLS.LCTR_SCHDLNM , TLLS.LCTR_SCHDL_SEQ , CASE WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('10', '20') AND TLLS.LCTR_SCHDL_SEQ = 8 THEN 'M' WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('10', '20') AND TLLS.LCTR_SCHDL_SEQ = 15 THEN 'L' WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('11', '21') THEN CASE WHEN (SELECT COUNT(1) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = TLLS.SBJCT_ID AND DELYN = 'N') = 15 THEN CASE WHEN TLLS.LCTR_SCHDL_SEQ = 8 THEN 'M' WHEN TLLS.LCTR_SCHDL_SEQ = 15 THEN 'L' END WHEN TLLS.LCTR_SCHDL_SEQ = (SELECT MAX(LCTR_SCHDL_SEQ) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = TLLS.SBJCT_ID AND DELYN = 'N') THEN 'L' END END AS TKEXAM_TYCD , CASE WHEN DATE_FORMAT(NOW(), '%Y%m%d') < IFNULL(TLLS.LCTR_RCG_SYMD, LCTR_SYMD) THEN 'READY' WHEN DATE_FORMAT(NOW(), '%Y%m%d') BETWEEN IFNULL(TLLS.LCTR_RCG_SYMD, LCTR_SYMD) AND IFNULL(TLLS.LCTR_RCG_EYMD, LCTR_EYMD) THEN 'PROGRESS' WHEN DATE_FORMAT(NOW(), '%Y%m%d') > IFNULL(TLLS.LCTR_RCG_EYMD, LCTR_EYMD) THEN 'END' ELSE 'READY' END AS LESSON_SCHEDULE_PROGRESS FROM TB_LMS_SBJCT_LCTR_SCHDL TLLS INNER JOIN TB_LMS_SBJCT TLCC ON TLLS.SBJCT_ID = TLCC.SBJCT_ID INNER JOIN SBJCT_PROF TLCCTR ON TLCC.SBJCT_ID = TLCCTR.SBJCT_ID AND TLCCTR.USER_ID = #{userId} AND TLCCTR.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT') INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN TLTCCR ON TLCC.SBJCT_ID = TLTCCR.SBJCT_ID INNER JOIN CRS_SMSTR TLT ON TLTCCR.CRS_SMSTR_ID = TLT.CRS_SMSTR_ID AND TLT.ORG_ID = #{orgId} WHERE 1 = 1 AND DEPT_CD = (SELECT DEPT_CD FROM TB_LMS_USR WHERE USER_ID = #{userId})
AND TLCC.SBJCT_ID IN (#{lastYear}, #{year})
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
) SCH WHERE TKEXAM_TYCD IS NULL AND LESSON_SCHEDULE_PROGRESS IN ('PROGRESS', 'END') AND LCTR_SCHDL_SEQ != '16' ) SELECT A.DEPT_CD , A.DEPTNM , A.LCTR_SCHDL_SEQ , IFNULL(ROUND(SUM(IFNULL(A.LAST_YEAR_ATTEND_CNT / LAST_YEAR_STD_CNT, 0)) / (SELECT COUNT(DISTINCT SBJCT_ID) FROM STD_INFO WHERE SBJCT_ID = #{lastYear} AND DEPT_CD = A.DEPT_CD), 2), 0) AS LAST_YEAR_AVG_ATTEND_RATE , IFNULL(ROUND(SUM(IFNULL(A.THIS_YEAR_ATTEND_CNT / THIS_YEAR_STD_CNT, 0)) / (SELECT COUNT(DISTINCT SBJCT_ID) FROM STD_INFO WHERE SBJCT_ID = #{year} AND DEPT_CD = A.DEPT_CD), 2), 0) AS THIS_YEAR_AVG_ATTEND_RATE FROM ( SELECT LS.DEPT_CD , LS.DEPTNM , LS.SBJCT_ID , LS.SBJCTNM , LS.LCTR_SCHDL_SEQ , LS.LCTR_SCHDL_ID , IFNULL(SUM(IF(LS.SBJCT_ID = #{lastYear}, PRGRT, 0)), 0) AS LAST_YEAR_ATTEND_CNT , IFNULL(SUM(IF(LS.SBJCT_ID = #{year}, PRGRT, 0)), 0) AS THIS_YEAR_ATTEND_CNT , IFNULL((SELECT COUNT(LCTR_SCHDL_ID) FROM LESSON_SCHEDULE LST WHERE LST .SBJCT_ID = LS.SBJCT_ID GROUP BY LST.SBJCT_ID), 0) LESSON_CNT , IFNULL((SELECT COUNT(USER_ID) FROM STD_INFO ST WHERE SBJCT_ID = #{lastYear} AND ST.SBJCT_ID = LS.SBJCT_ID GROUP BY ST.SBJCT_ID), 0) LAST_YEAR_STD_CNT , IFNULL((SELECT COUNT(USER_ID) FROM STD_INFO ST WHERE SBJCT_ID = #{year} AND ST.SBJCT_ID = LS.SBJCT_ID GROUP BY ST.SBJCT_ID), 0) THIS_YEAR_STD_CNT FROM LESSON_SCHEDULE LS LEFT JOIN TB_LEARNER_WEEK_PROG TLWP ON LS.SBJCT_ID = TLWP.SBJCT_ID AND LS.LCTR_SCHDL_SEQ = TLWP.LCTR_SCHDL_SEQ GROUP BY LS.DEPT_CD , LS.DEPTNM , LS.SBJCT_ID , LS.SBJCTNM , LS.LCTR_SCHDL_SEQ , LS.LCTR_SCHDL_ID ) A GROUP BY A.DEPT_CD , A.DEPTNM , A.LCTR_SCHDL_SEQ

/* SQL ID : ApiDAO.selectDeanDepartPerWeekAttend 설 명 : 학과장 학과별 주차별 출석현황 조회 */ WITH STD_INFO AS ( SELECT TLCC.DEPT_CD , TLCC.SBJCT_ID , TLCC.SBJCT_ID , TLS.STD_ID , TLS.USER_ID FROM TB_LMS_SBJCT TLCC INNER JOIN TB_LMS_ATNDLC_SBJCT TLS ON TLCC.SBJCT_ID = TLS.SBJCT_ID INNER JOIN TB_LMS_USER_ACNT THUL ON TLS.USER_ID = THUL.USER_ID AND THUL.ACNT_STSCD = 'U' AND TLS.ATNDLC_STSCD = 'S' /* 승인상태 */ AND TLS.AUDITYN = 'N' /* 청강생여부 */ AND TLS.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND TLS.ORG_ID = #{orgId} WHERE 1 = 1 AND TLCC.DEPT_CD = (SELECT DEPT_CD FROM TB_LMS_USR WHERE USER_ID = #{userId})
AND TLCC.SBJCT_ID IN (#{lastYear}, #{year})
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
), LESSON_SCHEDULE AS ( SELECT SCH.* FROM ( SELECT DISTINCT TLLS.SBJCT_ID , TLCC.SBJCTNM , TLCC.DEPT_CD , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD THUDC WHERE THUDC.DEPT_CD = TLCC.DEPT_CD) AS DEPTNM , TLCC.SBJCT_ID , TLLS.LCTR_SCHDL_ID , TLLS.LCTR_SCHDLNM , TLLS.LCTR_SCHDL_SEQ , CASE WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('10', '20') AND TLLS.LCTR_SCHDL_SEQ = 8 THEN 'M' WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('10', '20') AND TLLS.LCTR_SCHDL_SEQ = 15 THEN 'L' WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('11', '21') THEN CASE WHEN (SELECT COUNT(1) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = TLLS.SBJCT_ID AND DELYN = 'N') = 15 THEN CASE WHEN TLLS.LCTR_SCHDL_SEQ = 8 THEN 'M' WHEN TLLS.LCTR_SCHDL_SEQ = 15 THEN 'L' END WHEN TLLS.LCTR_SCHDL_SEQ = (SELECT MAX(LCTR_SCHDL_SEQ) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = TLLS.SBJCT_ID AND DELYN = 'N') THEN 'L' END END AS TKEXAM_TYCD , CASE WHEN DATE_FORMAT(NOW(), '%Y%m%d') < IFNULL(TLLS.LCTR_RCG_SYMD, LCTR_SYMD) THEN 'READY' WHEN DATE_FORMAT(NOW(), '%Y%m%d') BETWEEN IFNULL(TLLS.LCTR_RCG_SYMD, LCTR_SYMD) AND IFNULL(TLLS.LCTR_RCG_EYMD, LCTR_EYMD) THEN 'PROGRESS' WHEN DATE_FORMAT(NOW(), '%Y%m%d') > IFNULL(TLLS.LCTR_RCG_EYMD, LCTR_EYMD) THEN 'END' ELSE 'READY' END AS LESSON_SCHEDULE_PROGRESS FROM TB_LMS_SBJCT_LCTR_SCHDL TLLS INNER JOIN TB_LMS_SBJCT TLCC ON TLLS.SBJCT_ID = TLCC.SBJCT_ID INNER JOIN SBJCT_PROF TLCCTR ON TLCC.SBJCT_ID = TLCCTR.SBJCT_ID AND TLCCTR.USER_ID = #{userId} AND TLCCTR.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT') INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN TLTCCR ON TLCC.SBJCT_ID = TLTCCR.SBJCT_ID INNER JOIN CRS_SMSTR TLT ON TLTCCR.CRS_SMSTR_ID = TLT.CRS_SMSTR_ID AND TLT.ORG_ID = #{orgId} WHERE 1 = 1 AND DEPT_CD = (SELECT DEPT_CD FROM TB_LMS_USR WHERE USER_ID = #{userId})
AND SBJCT_ID IN (#{lastYear}, #{year})
AND SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND CRS_ID = #{semester}
AND CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
) SCH WHERE TKEXAM_TYCD IS NULL AND LESSON_SCHEDULE_PROGRESS IN ('PROGRESS', 'END') AND LCTR_SCHDL_SEQ != '16' ) SELECT A.DEPT_CD , A.DEPTNM , A.LCTR_SCHDL_SEQ , IFNULL(ROUND(SUM(IFNULL(A.LAST_YEAR_ATTEND_CNT / LAST_YEAR_STD_CNT, 0)) / (SELECT COUNT(DISTINCT DEPT_CD) FROM STD_INFO WHERE SBJCT_ID = #{lastYear} AND DEPT_CD = A.DEPT_CD), 2), 0) AS LAST_YEAR_AVG_ATTEND_RATE , IFNULL(ROUND(SUM(IFNULL(A.THIS_YEAR_ATTEND_CNT / THIS_YEAR_STD_CNT, 0)) / (SELECT COUNT(DISTINCT DEPT_CD) FROM STD_INFO WHERE SBJCT_ID = #{year} AND DEPT_CD = A.DEPT_CD), 2), 0) AS THIS_YEAR_AVG_ATTEND_RATE FROM ( SELECT LS.DEPT_CD , LS.DEPTNM , LS.SBJCT_ID , LS.SBJCTNM , LS.LCTR_SCHDL_SEQ , LS.LCTR_SCHDL_ID , IFNULL(SUM(IF(LS.SBJCT_ID = #{lastYear}, PRGRT, 0)), 0) AS LAST_YEAR_ATTEND_CNT , IFNULL(SUM(IF(LS.SBJCT_ID = #{year}, PRGRT, 0)), 0) AS THIS_YEAR_ATTEND_CNT , IFNULL((SELECT COUNT(LCTR_SCHDL_ID) FROM LESSON_SCHEDULE LST WHERE LST.SBJCT_ID = LS.SBJCT_ID GROUP BY LST.SBJCT_ID), 0) LESSON_CNT , IFNULL((SELECT COUNT(USER_ID) FROM STD_INFO ST WHERE SBJCT_ID = #{lastYear} AND ST.SBJCT_ID = LS.SBJCT_ID GROUP BY ST.SBJCT_ID), 0) LAST_YEAR_STD_CNT , IFNULL((SELECT COUNT(USER_ID) FROM STD_INFO ST WHERE SBJCT_ID = #{year} AND ST.SBJCT_ID = LS.SBJCT_ID GROUP BY ST.SBJCT_ID), 0) THIS_YEAR_STD_CNT FROM LESSON_SCHEDULE LS LEFT JOIN TB_LEARNER_WEEK_PROG TLWP ON LS.SBJCT_ID = TLWP.SBJCT_ID AND LS.LCTR_SCHDL_SEQ = TLWP.LCTR_SCHDL_SEQ GROUP BY LS.DEPT_CD , LS.DEPTNM , LS.SBJCT_ID , LS.SBJCTNM , LS.LCTR_SCHDL_SEQ , LS.LCTR_SCHDL_ID ) A GROUP BY A.DEPT_CD , A.DEPTNM , A.LCTR_SCHDL_SEQ

/* SQL ID : ApiDAO.selectTotalPerWeekAttend 설 명 : 전체 주차별 출석현황 조회 */ WITH STD_INFO AS ( SELECT TLCC.SBJCT_ID , TLCC.DEPT_CD , TLCC.SBJCT_ID , TLS.STD_ID , TLS.USER_ID FROM TB_LMS_SBJCT TLCC INNER JOIN TB_LMS_ATNDLC_SBJCT TLS ON TLCC.SBJCT_ID = TLS.SBJCT_ID INNER JOIN TB_LMS_USER_ACNT THUL ON TLS.USER_ID = THUL.USER_ID AND THUL.ACNT_STSCD = 'U' AND TLS.ATNDLC_STSCD = 'S' /* 승인상태 */ AND TLS.AUDITYN = 'N' /* 청강생여부 */ AND TLS.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND TLS.ORG_ID = #{orgId} WHERE 1 = 1
AND TLCC.SBJCT_ID IN (#{lastYear}, #{year})
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
) SELECT A.LCTR_SCHDL_SEQ , ROUND(IFNULL(SUM(LAST_PER_WEEK_RATIO) / (SELECT COUNT(DISTINCT SBJCT_ID) FROM STD_INFO WHERE SBJCT_ID = #{lastYear}), 0), 2) AS LAST_YEAR_AVG_ATTEND_RATE , ROUND(IFNULL(SUM(THIS_PER_WEEK_RATIO) / (SELECT COUNT(DISTINCT SBJCT_ID) FROM STD_INFO WHERE SBJCT_ID = #{year}), 0), 2) AS THIS_YEAR_AVG_ATTEND_RATE FROM ( SELECT TLWP.SBJCT_ID , TLWP.LCTR_SCHDL_SEQ , IFNULL(IFNULL(SUM(IF(TLWP.SBJCT_ID = #{lastYear}, PRGRT, 0)), 0) / IFNULL((SELECT COUNT(USER_ID) FROM STD_INFO ST WHERE SBJCT_ID = #{lastYear} AND ST.SBJCT_ID = TLWP.SBJCT_ID), 0), 0) AS LAST_PER_WEEK_RATIO , IFNULL(IFNULL(SUM(IF(TLWP.SBJCT_ID = #{year}, PRGRT, 0)), 0) / IFNULL((SELECT COUNT(USER_ID) FROM STD_INFO ST WHERE SBJCT_ID = #{year} AND ST.SBJCT_ID = TLWP.SBJCT_ID), 0), 0) AS THIS_PER_WEEK_RATIO FROM TB_LEARNER_WEEK_PROG TLWP WHERE 1 = 1
AND TLWP.SBJCT_ID IN (#{lastYear}, #{year})
AND TLWP.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLWP.CRS_ID = #{semester}
AND TLWP.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
GROUP BY TLWP.SBJCT_ID , TLWP.LCTR_SCHDL_SEQ ) A GROUP BY A.LCTR_SCHDL_SEQ ORDER BY A.LCTR_SCHDL_SEQ

/* SQL ID : ApiDAO.selectPerWeekAttend 설 명 : 주차별 출석현황 조회 */ SELECT A.LCTR_SCHDL_SEQ , IFNULL(ROUND(CMPL_WEEK_CNT_C / TOT_WEEK_CNT_C * 100, 2), 0) AS COLLEAGE_AVG_ATTEND_RATE , IFNULL(ROUND(CMPL_WEEK_CNT_G / TOT_WEEK_CNT_G * 100, 2), 0) AS GRAD_AVG_ATTEND_RATE FROM TB_LEARNER_WEEK_PROG_SUM A
AND A.SBJCT_ID = #{year}
AND A.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND A.CRS_ID = #{semester}
AND A.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
ORDER BY A.LCTR_SCHDL_SEQ

/* SQL ID : ApiDAO.selectProfSubjectPerWeekAttend 설 명 : 교수 과목별 출석현황 조회 */ WITH STD_INFO AS ( SELECT TLCC.SBJCT_ID , TLS.STD_ID , TLS.USER_ID FROM TB_LMS_SBJCT TLCC INNER JOIN SBJCT_PROF TLCCTR ON TLCC.SBJCT_ID = TLCCTR.SBJCT_ID AND TLCCTR.USER_ID = #{userId} AND TLCCTR.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT') INNER JOIN TB_LMS_ATNDLC_SBJCT TLS ON TLCC.SBJCT_ID = TLS.SBJCT_ID INNER JOIN TB_LMS_USER_ACNT THUL ON TLS.USER_ID = THUL.USER_ID AND THUL.ACNT_STSCD = 'U' AND TLS.ATNDLC_STSCD = 'S' /* 승인상태 */ AND TLS.AUDITYN = 'N' /* 청강생여부 */ AND TLS.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND TLS.ORG_ID = #{orgId}
AND TLCC.SBJCT_ID = #{year}
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
), LESSON_SCHEDULE AS ( SELECT SCH.* FROM ( SELECT DISTINCT TLLS.SBJCT_ID , TLCC.SBJCTNM , TLLS.LCTR_SCHDL_ID , TLLS.LCTR_SCHDLNM , TLLS.LCTR_SCHDL_SEQ , CASE WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('10', '20') AND TLLS.LCTR_SCHDL_SEQ = 8 THEN 'M' WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('10', '20') AND TLLS.LCTR_SCHDL_SEQ = 15 THEN 'L' WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('11', '21') THEN CASE WHEN (SELECT COUNT(1) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = TLLS.SBJCT_ID AND DELYN = 'N') = 15 THEN CASE WHEN TLLS.LCTR_SCHDL_SEQ = 8 THEN 'M' WHEN TLLS.LCTR_SCHDL_SEQ = 15 THEN 'L' END WHEN TLLS.LCTR_SCHDL_SEQ = (SELECT MAX(LCTR_SCHDL_SEQ) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = TLLS.SBJCT_ID AND DELYN = 'N') THEN 'L' END END AS TKEXAM_TYCD , CASE WHEN DATE_FORMAT(NOW(), '%Y%m%d') < IFNULL(TLLS.LCTR_RCG_SYMD, LCTR_SYMD) THEN 'READY' WHEN DATE_FORMAT(NOW(), '%Y%m%d') BETWEEN IFNULL(TLLS.LCTR_RCG_SYMD, LCTR_SYMD) AND IFNULL(TLLS.LCTR_RCG_EYMD, LCTR_EYMD) THEN 'PROGRESS' WHEN DATE_FORMAT(NOW(), '%Y%m%d') > IFNULL(TLLS.LCTR_RCG_EYMD, LCTR_EYMD) THEN 'END' ELSE 'READY' END AS LESSON_SCHEDULE_PROGRESS FROM TB_LMS_SBJCT_LCTR_SCHDL TLLS INNER JOIN TB_LMS_SBJCT TLCC ON TLLS.SBJCT_ID = TLCC.SBJCT_ID INNER JOIN SBJCT_PROF TLCCTR ON TLCC.SBJCT_ID = TLCCTR.SBJCT_ID AND TLCCTR.USER_ID = #{userId} AND TLCCTR.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT') INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN TLTCCR ON TLCC.SBJCT_ID = TLTCCR.SBJCT_ID INNER JOIN CRS_SMSTR TLT ON TLTCCR.CRS_SMSTR_ID = TLT.CRS_SMSTR_ID WHERE 1 = 1
AND TLCC.SBJCT_ID = #{year}
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
) SCH WHERE TKEXAM_TYCD IS NULL AND LESSON_SCHEDULE_PROGRESS IN ('PROGRESS', 'END') ) SELECT SBJCT_ID , SBJCTNM , ROUND(IFNULL(SUM(COMPLETE_LATE_CNT / STD_CNT) / (SELECT COUNT(LCTR_SCHDL_ID) FROM LESSON_SCHEDULE WHERE SBJCT_ID = AA.SBJCT_ID GROUP BY SBJCT_ID), 0), 2) AS SUBJECT_ATTEND_RATE FROM ( SELECT A.SBJCT_ID , A.SBJCTNM , B.LCTR_SCHDL_SEQ , SUM(PRGRT) AS COMPLETE_LATE_CNT , (SELECT COUNT(USER_ID) FROM STD_INFO ST WHERE ST .SBJCT_ID = A.SBJCT_ID GROUP BY ST.SBJCT_ID) STD_CNT FROM LESSON_SCHEDULE A LEFT JOIN TB_LEARNER_WEEK_PROG B ON A.SBJCT_ID = B.SBJCT_ID AND A.LCTR_SCHDL_SEQ = B.LCTR_SCHDL_SEQ GROUP BY A.SBJCT_ID, A.SBJCTNM, A.LCTR_SCHDL_SEQ ) AA GROUP BY SBJCT_ID, SBJCTNM

/* SQL ID : ApiDAO.selectDeanSubjectPerWeekAttend 설 명 : 학과장 과목별 출석현황 조회 */ WITH STD_INFO AS ( SELECT TLCC.SBJCT_ID , TLS.STD_ID , TLS.USER_ID FROM TB_LMS_SBJCT TLCC INNER JOIN TB_LMS_ATNDLC_SBJCT TLS ON TLCC.SBJCT_ID = TLS.SBJCT_ID INNER JOIN TB_LMS_USER_ACNT THUL ON TLS.USER_ID = THUL.USER_ID AND THUL.ACNT_STSCD = 'U' AND TLS.ATNDLC_STSCD = 'S' /* 승인상태 */ AND TLS.AUDITYN = 'N' /* 청강생여부 */ AND TLS.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND TLS.ORG_ID = #{orgId} WHERE 1 = 1 AND TLCC.DEPT_CD = (SELECT DEPT_CD FROM TB_LMS_USR WHERE USER_ID = #{userId})
AND TLCC.SBJCT_ID IN (#{lastYear}, #{year})
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
), LESSON_SCHEDULE AS ( SELECT SCH.* FROM ( SELECT DISTINCT TLLS.SBJCT_ID , TLCC.SBJCTNM , TLLS.LCTR_SCHDL_ID , TLLS.LCTR_SCHDLNM , TLLS.LCTR_SCHDL_SEQ , CASE WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('10', '20') AND TLLS.LCTR_SCHDL_SEQ = 8 THEN 'M' WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('10', '20') AND TLLS.LCTR_SCHDL_SEQ = 15 THEN 'L' WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('11', '21') THEN CASE WHEN (SELECT COUNT(1) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = TLLS.SBJCT_ID AND DELYN = 'N') = 15 THEN CASE WHEN TLLS.LCTR_SCHDL_SEQ = 8 THEN 'M' WHEN TLLS.LCTR_SCHDL_SEQ = 15 THEN 'L' END WHEN TLLS.LCTR_SCHDL_SEQ = (SELECT MAX(LCTR_SCHDL_SEQ) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = TLLS.SBJCT_ID AND DELYN = 'N') THEN 'L' END END AS TKEXAM_TYCD , CASE WHEN DATE_FORMAT(NOW(), '%Y%m%d') < IFNULL(TLLS.LCTR_RCG_SYMD, LCTR_SYMD) THEN 'READY' WHEN DATE_FORMAT(NOW(), '%Y%m%d') BETWEEN IFNULL(TLLS.LCTR_RCG_SYMD, LCTR_SYMD) AND IFNULL(TLLS.LCTR_RCG_EYMD, LCTR_EYMD) THEN 'PROGRESS' WHEN DATE_FORMAT(NOW(), '%Y%m%d') > IFNULL(TLLS.LCTR_RCG_EYMD, LCTR_EYMD) THEN 'END' ELSE 'READY' END AS LESSON_SCHEDULE_PROGRESS FROM TB_LMS_SBJCT_LCTR_SCHDL TLLS INNER JOIN TB_LMS_SBJCT TLCC ON TLLS.SBJCT_ID = TLCC.SBJCT_ID INNER JOIN SBJCT_PROF TLCCTR ON TLCC.SBJCT_ID = TLCCTR.SBJCT_ID AND TLCCTR.USER_ID = #{userId} AND TLCCTR.PROF_TYCD IN ('PROFESSOR', 'ASSISTANT') INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN TLTCCR ON TLCC.SBJCT_ID = TLTCCR.SBJCT_ID INNER JOIN CRS_SMSTR TLT ON TLTCCR.CRS_SMSTR_ID = TLT.CRS_SMSTR_ID WHERE 1 = 1 AND TLCC.DEPT_CD = (SELECT DEPT_CD FROM TB_LMS_USR WHERE USER_ID = #{userId})
AND TLCC.SBJCT_ID IN (#{lastYear}, #{year})
AND TLCC.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLCC.CRS_ID = #{semester}
AND TLCC.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
) SCH WHERE TKEXAM_TYCD IS NULL AND LESSON_SCHEDULE_PROGRESS IN ('PROGRESS', 'END') ) SELECT SBJCT_ID , SBJCTNM , ROUND(IFNULL(SUM(COMPLETE_LATE_CNT / STD_CNT) / (SELECT COUNT(LCTR_SCHDL_ID) FROM LESSON_SCHEDULE WHERE SBJCT_ID = AA.SBJCT_ID GROUP BY SBJCT_ID), 0), 2) AS SUBJECT_ATTEND_RATE FROM ( SELECT A.SBJCT_ID , A.SBJCTNM , B.LCTR_SCHDL_SEQ , SUM(PRGRT) AS COMPLETE_LATE_CNT , (SELECT COUNT(USER_ID) FROM STD_INFO ST WHERE ST.SBJCT_ID = A.SBJCT_ID GROUP BY ST.SBJCT_ID) STD_CNT FROM LESSON_SCHEDULE A LEFT JOIN TB_LEARNER_WEEK_PROG B ON A.SBJCT_ID = B.SBJCT_ID AND A.LCTR_SCHDL_SEQ = B.LCTR_SCHDL_SEQ GROUP BY A.SBJCT_ID, A.SBJCTNM, A.LCTR_SCHDL_SEQ ) AA GROUP BY SBJCT_ID, SBJCTNM

/* SQL ID : ApiDAO.selectStuCrsCreNmList 설 명 : 학생 수강 과목 조회 */ SELECT TLP.USER_ID , TLCC.CRS_ID , TLP.SBJCT_ID , TLP.SBJCTNM , TLP.DVCLAS_NO , TLP.LRN_WKNO , TLP.TOT_WEEK_CNT , CASE WHEN TLP.PRGRT = '100' THEN TLP.PRGRT WHEN TLP.PRGRT != '100' THEN CASE WHEN TLP.PRGRT = '0' THEN TLP.PRGRT WHEN TLP.PRGRT != '0' THEN IFNULL(FORMAT(TLP.PRGRT, 2), 0) END END PRGRT , TLP.LCTRRM_URL FROM TB_LMS_LRN_PRGRT TLP INNER JOIN TB_LMS_SBJCT TLCC ON TLP.SBJCT_ID = TLCC.SBJCT_ID AND TLCC.USEYN = 'Y' AND TLCC.DELYN = 'N' INNER JOIN TB_LMS_USR THUI ON TLP.USER_ID = THUI.USER_ID AND THUI.SCHREG_GBN_CD = '01'
AND TLP.SBJCT_ID = #{year}
AND TLP.SBJCT_ID = (SELECT DGRS_YR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLP.CRS_ID = #{semester}
AND TLP.CRS_ID = ( SELECT DGRS_SMSTR FROM CRS_SMSTR WHERE SMSTR_STSCD = 'SERVICE' AND NOW_SMSTRYN = 'Y' AND ORG_ID = #{orgId} AND DGRS_YR <= (SELECT DATE_FORMAT(NOW(), '%Y')))
AND TLP.USER_ID = #{userId}

mapper.insert:
/* SQL ID : ApiDAO.insertStdProgressRatio 설 명 : 전체 학생 과목별 진도율 입력 */ INSERT INTO TB_LMS_LRN_PRGRT ( LEARNER_PROG_ID /* 진도율통계ID */ , SBJCT_ID /* 과정개설코드 */ , SBJCT_ID /* 개설년도 */ , CRS_ID /* 개설기수 */ , DVCLAS_NO /* 분반번호 */ , UNIV_CD /* 학부대학원구분 */ , SBJCTNM /* 과정개설명 */ , USER_ID /* 사용자번호 */ , LRN_WKNO /* 학습주차주 */ , TOT_WEEK_CNT /* 전체주차주 */ , PRGRT /* 진도율 */ , LCTRRM_URL /* 강의실홈URL */ , FRST_INQ_DTTM /* 등록일 */ , MOD_DTTM /* 수정일 */ ) WITH CRS_STD_INFO AS ( SELECT TLCC.SBJCT_ID , TLCC.SBJCTNM , TLCC.SBJCT_ID , TLCC.CRS_ID , TLCC.DVCLAS_NO , TLCC.UNIV_CD , TLS.STD_ID , TLS.USER_ID FROM TB_LMS_SBJCT TLCC INNER JOIN TB_LMS_ATNDLC_SBJCT TLS ON TLCC.SBJCT_ID = TLS.SBJCT_ID AND TLCC.DELYN = 'N' INNER JOIN TB_LMS_USER_ACNT THUL ON TLS.USER_ID = THUL.USER_ID AND THUL.ACNT_STSCD = 'U' AND TLS.ATNDLC_STSCD = 'S' /* 승인상태 */ AND TLS.AUDITYN = 'N' /* 청강생여부 */ AND TLS.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND TLS.ORG_ID = #{orgId} WHERE 1 = 1 AND TLCC.SBJCT_ID = YEAR(NOW()) ), LESSON_SCHEDULE AS ( SELECT * FROM ( SELECT TLLS.SBJCT_ID , CSI.SBJCTNM , CSI.SBJCT_ID , CSI.CRS_ID , CSI.DVCLAS_NO , CSI.UNIV_CD , TLLS.LCTR_SCHDL_ID , TLLS.LCTR_SCHDLNM , TLTCCRT.CRS_SMSTR_ID , CASE WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('10', '20') AND TLLS.LCTR_SCHDL_SEQ = 8 THEN 'M' WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('10', '20') AND TLLS.LCTR_SCHDL_SEQ = 15 THEN 'L' WHEN RPAD(TLT.DGRS_SMSTR, 2, '0') IN ('11', '21') THEN CASE WHEN (SELECT COUNT(1) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = TLLS.SBJCT_ID AND DELYN = 'N') = 15 THEN CASE WHEN TLLS.LCTR_SCHDL_SEQ = 8 THEN 'M' WHEN TLLS.LCTR_SCHDL_SEQ = 15 THEN 'L' END WHEN TLLS.LCTR_SCHDL_SEQ = (SELECT MAX(LCTR_SCHDL_SEQ) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE SBJCT_ID = TLLS.SBJCT_ID AND DELYN = 'N') THEN 'L' END END AS TKEXAM_TYCD , CASE WHEN DATE_FORMAT(NOW(), '%Y%m%d') < IFNULL(TLLS.LCTR_RCG_SYMD, TLLS.LCTR_SYMD) THEN 'READY' WHEN DATE_FORMAT(NOW(), '%Y%m%d') BETWEEN IFNULL(TLLS.LCTR_RCG_SYMD, TLLS.LCTR_SYMD) AND IFNULL(TLLS.LCTR_RCG_EYMD, TLLS.LCTR_EYMD) THEN 'PROGRESS' WHEN DATE_FORMAT(NOW(), '%Y%m%d') > IFNULL(TLLS.LCTR_RCG_EYMD, TLLS.LCTR_EYMD) THEN 'END' ELSE 'READY' END AS LESSON_SCHEDULE_PROGRESS FROM TB_LMS_SBJCT_LCTR_SCHDL TLLS INNER JOIN ( SELECT DISTINCT SBJCT_ID , SBJCTNM , SBJCT_ID , CRS_ID , DVCLAS_NO , UNIV_CD FROM CRS_STD_INFO ) CSI ON TLLS.SBJCT_ID = CSI.SBJCT_ID INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN TLTCCRT ON TLLS.SBJCT_ID = TLTCCRT.SBJCT_ID INNER JOIN CRS_SMSTR TLT ON TLTCCRT.CRS_SMSTR_ID = TLT.CRS_SMSTR_ID AND TLT.ORG_ID = #{orgId} WHERE 1 = 1 AND TLCC.SBJCT_ID = YEAR(NOW()) ) SCH WHERE TKEXAM_TYCD IS NULL AND LESSON_SCHEDULE_PROGRESS IN ('PROGRESS', 'END') ) SELECT LEARNER_PROG_ID /* 진도율통계ID */ , SBJCT_ID /* 과정개설코드 */ , SBJCT_ID /* 개설년도 */ , CRS_ID /* 개설기수 */ , DVCLAS_NO /* 분반번호 */ , UNIV_CD /* 학부대학원구분 */ , SBJCTNM /* 과정개설명 */ , USER_ID /* 사용자번호 */ , LRN_WKNO /* 학습주차주 */ , CRS_LESSON_CNT /* 전체주차주 */ , IF (PRGRT = 0.0000, 0, IF(PRGRT = 100.0000, 100, PRGRT)) /* 진도율 */ , LCTRRM_URL /* 강의실홈URL */ , DATE_FORMAT(NOW(), '%Y%m%d%H%i') /* 등록일 */ , DATE_FORMAT(NOW(), '%Y%m%d%H%i') /* 수정일 */ FROM ( SELECT CONCAT(SBJCT_ID, SBJCT_ID, CRS_ID, DVCLAS_NO, USER_ID) AS LEARNER_PROG_ID , SBJCT_ID , SBJCT_ID , CRS_ID , DVCLAS_NO , UNIV_CD , SBJCTNM , USER_ID , SUM(STD_PROGRESS_VALUE) AS CMPL_WEEK_CN , CRS_LESSON_CNT , SUM(STD_PROGRESS_VALUE) / CRS_LESSON_CNT * 100 AS PRGRT
, CONCAT('/crs/crsHomeStd.do&#63;crsCreCd=', SBJCT_ID) AS LCTRRM_URL /* 강의실홈URL */
FROM ( SELECT LS.SBJCT_ID , LS.LCTR_SCHDL_ID , LS.LCTR_SCHDLNM , LS.SBJCTNM , LS.SBJCT_ID , LS.CRS_ID , LS.DVCLAS_NO , LS.UNIV_CD , TLLSS.USER_ID , IF(IFNULL(TLLSS.ATNDLC_STSCD, 'NOSTUDY') IN ('COMPLETE', 'LATE'), 1, 0) AS STD_PROGRESS_VALUE /* 학부,대학원 학생 과목별 진도 값 */ , (SELECT COUNT(LCTR_SCHDL_ID) FROM LESSON_SCHEDULE WHERE SBJCT_ID = LS.SBJCT_ID GROUP BY SBJCT_ID ) AS CRS_LESSON_CNT /* 과목별 총 주차수 */ FROM LESSON_SCHEDULE LS LEFT JOIN TB_LMS_LESSON_STUDY_STATE TLLSS ON LS.LCTR_SCHDL_ID = TLLSS.LCTR_SCHDL_ID ) A WHERE USER_ID IS NOT NULL GROUP BY SBJCT_ID , SBJCTNM , SBJCT_ID , CRS_ID , DVCLAS_NO , UNIV_CD , USER_ID ) AA ON DUPLICATE KEY UPDATE LRN_WKNO = AA.LRN_WKNO /* 학습주차주 */ , TOT_WEEK_CNT = AA.CRS_LESSON_CNT /* 전체주차주 */ , PRGRT = IF (AA.PRGRT = 0.0000, 0, IF(AA.PRGRT = 100.0000, 100, AA.PRGRT)) /* 진도율 */ , LCTRRM_URL = AA.LCTRRM_URL /* 강의실홈URL */ , MOD_DTTM = DATE_FORMAT(NOW(), '%Y%m%d%H%i') /* 수정일 */

mapper.select:
/*
     SQL ID : ApiDAO.selectWeekCount 
     설 명 : 주차별 수강 현황(카운트)
*/
SELECT IFNULL(COUNT(1), 0) AS COUNT_INFO
  FROM TB_STAT_STDY_WEEKSUM TSSW



            AND TSSW.CONN_YEAR = #{connYear}





            AND TSSW.CONN_TERM = #{connTerm}






            AND ( DATE_FORMAT(TSSW.MOD_DTTM, "%Y%m%d")
                BETWEEN DATE_FORMAT(#{todayDttm}, "%Y%m%d") AND DATE_FORMAT(ADDDATE(NOW(), INTERVAL 1 DAY), "%Y%m%d") )





            AND TSSW.SBJCT_LCTR_WKNO != #{ltOmitWeek}





            AND TSSW.SBJCT_LCTR_WKNO = #{ltWeek}

/* SQL ID : ApiDAO.selectWeekList 설 명 : 주차별 수강 현황(목록) */ SELECT TSSW.SBJCT_ID /* 년도 */ , TSSW.CRS_ID /* 학기 */ , TSSW.USER_ID /* 사용자 번호 */ , TSSW.SBJCT_LCTR_WKNO /* 주차 */ , IFNULL(TSSW.APLY_CRDTS, 0) AS APLY_CRDTS /* 신청학점 */ , IFNULL(TSSW.CNTNDAY_CNT, 0) AS CNTNDAY_CNT /* 접속일수합계 */ , IFNULL(TSSW.CONN_DAY_SUM, 0) AS CONN_DAY_SUM /* 접속일수누적합계 */ , IFNULL(TSSW.CONN_TM, 0) AS CONN_TM /* 접속시간합계 */ , IFNULL(TSSW.CNTN_MNTS_SUM, 0) AS CNTN_MNTS_SUM /* 접속시간누적합계 */ , IFNULL(TSSW.CNTN_MNTS_DAY_AVG, 0) AS CNTN_MNTS_DAY_AVG /* 일접속시간 평균 */ , IFNULL(TSSW.CNTN_MNTS_DAY_STND_DVTN, 0) AS CNTN_MNTS_DAY_STND_DVTN /* 일접속시간 표준편차 */ , IFNULL(TSSW.CNTNDAY_INTVL_AVG, 0) AS CNTNDAY_INTVL_AVG /* 접속일간격 평균 */ , IFNULL(TSSW.CNTNDAY_INTVL_STND_DVTN, 0) AS CNTNDAY_INTVL_STND_DVTN /* 접속일간격 표준편차 */ , IFNULL(TSSW.WKEND_CNTNRT, 0) AS WKEND_CNTNRT /* 주간접속비율 */ , IFNULL(TSSW.WKDAYS_CNTNRT, 0) AS WKDAYS_CNTNRT /* 주중접속비율 */ , TSSW.FRST_INQ_DTTM /* 등록일 */ , TSSW.MOD_DTTM /* 수정일 */ FROM TB_STAT_STDY_WEEKSUM TSSW
AND TSSW.SBJCT_ID = #{connYear}
AND TSSW.CRS_ID = #{creTerm}
AND ( DATE_FORMAT(TSSW.MOD_DTTM, "%Y%m%d") BETWEEN DATE_FORMAT(#{todayDttm}, "%Y%m%d") AND DATE_FORMAT(ADDDATE(NOW(), INTERVAL 1 DAY), "%Y%m%d") )
AND TSSW.SBJCT_LCTR_WKNO != #{ltOmitWeek}
AND TSSW.SBJCT_LCTR_WKNO = #{ltWeek}
ORDER BY TSSW.USER_ID LIMIT #{firstIndex}, #{listScale}

mapper.sql:
SELECT A.SBJCT_ID , A.CRS_ID , A.DVCLAS_NO , A.CRS_ID , B.ASMT_ID , B.ASMT_TTL , B.SEND_START_DTTM , IF(EXT_SEND_ACPT_YN = 'Y' AND EXT_SEND_DTTM IS NOT NULL AND EXT_SEND_DTTM > SEND_END_DTTM, EXT_SEND_DTTM, SEND_END_DTTM) AS SEND_END_DTTM , IFNULL(B.DELYN, 'N') AS DELYN FROM TB_LMS_SBJCT A JOIN TB_LMS_ASMT B ON A.SBJCT_ID = B.SBJCT_ID JOIN TB_LMS_TERM_CRE_CRS_RLTN C ON A.SBJCT_ID = C.SBJCT_ID JOIN CRS_SMSTR D ON C.CRS_SMSTR_ID = D.CRS_SMSTR_ID AND D.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND A.SBJCT_TYCD = 'UNI'
AND A.SBJCT_ID = #{creYear}
AND A.CRS_ID = #{creTerm}
AND ( DATE_FORMAT(B.MOD_DTTM, "%Y%m%d") BETWEEN DATE_FORMAT(#{todayDttm}, "%Y%m%d") AND DATE_FORMAT(ADDDATE(NOW(), INTERVAL 1 DAY), "%Y%m%d") )

