SELECT A.SBJCT_ID , A.CRS_ID , A.DVCLAS_NO , A.CRS_ID , B.DSCS_ID , B.DSCS_TTL , IFNULL(B.EXTD_SDTTM, B.DSCS_SDTTM) AS DSCS_SDTTM , IFNULL(B.EXTD_EDTTM, B.DSCS_EDTTM) AS DSCS_EDTTM , IFNULL(B.DELYN, 'N') AS DELYN FROM TB_LMS_SBJCT A JOIN TB_LMS_DSCS B ON A.SBJCT_ID = B.SBJCT_ID JOIN TB_LMS_TERM_CRE_CRS_RLTN C ON A.SBJCT_ID = C.SBJCT_ID JOIN CRS_SMSTR D ON C.CRS_SMSTR_ID = D.CRS_SMSTR_ID AND D.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND A.SBJCT_TYCD = 'UNI'
