SELECT A.SBJCT_ID , A.CRS_ID , A.DVCLAS_NO , A.CRS_ID , C.EXAM_ID , C.EXAM_TTL , C.EXAM_SDTTM , IF(C.REEXAMYN = 'Y' AND C.RE_EXAM_END_DTTM IS NOT NULL AND C.RE_EXAM_END_DTTM > C.EXAM_EDTTM, C.RE_EXAM_END_DTTM, C.EXAM_EDTTM) AS EXAM_EDTTM , IFNULL(C.DELYN, 'N') AS DELYN FROM TB_LMS_SBJCT A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' INNER JOIN TB_LMS_EXAM_BSC C ON B.EXAM_ID = C.EXAM_ID AND C.REG_YN = 'Y'
AND C.EXAM_CTGRCD = 'QUIZ' AND C.EXAM_TYCD = 'QUIZ' AND C.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND A.SBJCT_TYCD = 'UNI'
