SELECT A.SBJCT_ID , A.CRS_ID , A.DVCLAS_NO , A.CRS_ID , C.SRVY_ID , C.SRVY_TTL , C.SRVY_SDTTM , C.RESCH_END_DTTM , IFNULL(C.DELYN, 'N') AS DELYN FROM TB_LMS_SBJCT A JOIN TB_LMS_RESCH_CRE_CRS_RLTN B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' JOIN TB_LMS_SRVY C ON B.SRVY_ID = C.SRVY_ID AND C.ORG_ID = #{orgId} AND C.DELYN = 'N' WHERE A.DELYN = 'N' AND A.SBJCT_TYCD = 'UNI'
