/* SQL ID : ApiDAO.selectLearnProgressCount 설 명 : 학습진도 카운트 */ SELECT IFNULL(COUNT(TLP.USER_ID), 0) AS COUNT_INFO FROM TB_LMS_LRN_PRGRT TLP INNER JOIN TB_LMS_SBJCT TLCC ON TLP.SBJCT_ID = TLCC.SBJCT_ID AND TLCC.USEYN = 'Y' AND TLCC.DELYN = 'N' INNER JOIN TB_LMS_USR THUI ON TLP.USER_ID = THUI.USER_ID AND THUI.SCHREG_GBN_CD = '01'
AND TLP.SBJCT_ID = #{year}
AND TLP.CRS_ID = #{semester}
AND ( DATE_FORMAT(TLP.MOD_DTTM, "%Y%m%d") BETWEEN DATE_FORMAT(#{todayDttm}, "%Y%m%d") AND DATE_FORMAT(ADDDATE(NOW(), INTERVAL 1 DAY), "%Y%m%d") )

/* SQL ID : ApiDAO.selectLearnProgressList 설 명 : 학습진도 목록 */ SELECT TLP.USER_ID , TLCC.CRS_ID , TLP.DVCLAS_NO , CASE WHEN TLP.PRGRT = '100' THEN TLP.PRGRT WHEN TLP.PRGRT != '100' THEN CASE WHEN TLP.PRGRT = '0' THEN TLP.PRGRT WHEN TLP.PRGRT != '0' THEN IFNULL(FORMAT(TLP.PRGRT, 2), 0) END END PRGRT FROM TB_LMS_LRN_PRGRT TLP INNER JOIN TB_LMS_SBJCT TLCC ON TLP.SBJCT_ID = TLCC.SBJCT_ID AND TLCC.USEYN = 'Y' AND TLCC.DELYN = 'N' INNER JOIN TB_LMS_USR THUI ON TLP.USER_ID = THUI.USER_ID AND THUI.SCHREG_GBN_CD = '01'
AND TLP.SBJCT_ID = #{year}
AND TLP.CRS_ID = #{semester}
AND ( DATE_FORMAT(TLP.MOD_DTTM, "%Y%m%d") BETWEEN DATE_FORMAT(#{todayDttm}, "%Y%m%d") AND DATE_FORMAT(ADDDATE(NOW(), INTERVAL 1 DAY), "%Y%m%d") )
LIMIT #{firstIndex}, #{listScale}

