SELECT B.ASMT_ID , B.ASMT_TTL , D.USER_ID , C.ASMT_SBMSN_ID , C.SBMSN_STSCD , C.RESEND_YN , C.FRST_INQ_DTTM , C.MOD_DTTM FROM TB_LMS_SBJCT A JOIN TB_LMS_ASMT B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' JOIN TB_LMS_ASMT_SBMSN C ON B.ASMT_ID = C.ASMT_ID AND C.DELYN = 'N' AND IFNULL(C.SBMSN_STSCD, 'NO') != 'NO' JOIN TB_LMS_ATNDLC_SBJCT D ON C.STD_ID = D.STD_ID AND D.ATNDLC_STSCD = 'S' /* 승인상태 */ AND D.AUDITYN = 'N' /* 청강생여부 */ AND D.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND D.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND A.USEYN = 'Y'
AND A.SBJCT_ID = #{year}
AND A.CRS_ID = #{semester}
AND ( DATE_FORMAT(C.FRST_INQ_DTTM, "%Y%m%d") BETWEEN DATE_FORMAT(#{todayDttm}, "%Y%m%d") AND DATE_FORMAT(ADDDATE(NOW(), INTERVAL 1 DAY), "%Y%m%d") )

