SELECT E.DSCS_ID , B.DSCS_TTL , D.USER_ID , E.FRST_INQ_DTTM , E.MOD_DTTM FROM TB_LMS_SBJCT A JOIN TB_LMS_DSCS B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' JOIN TB_LMS_DSCS_PTCP C ON B.DSCS_ID = C.DSCS_ID AND C.DELYN = 'N' JOIN TB_LMS_ATNDLC_SBJCT D ON C.STD_ID = D.STD_ID AND A.SBJCT_ID = D.SBJCT_ID AND D.ATNDLC_STSCD = 'S' /* 승인상태 */ AND D.AUDITYN = 'N' /* 청강생여부 */ AND D.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND D.ORG_ID = #{orgId} JOIN TB_LMS_DSCS_ATCL E ON B.DSCS_ID = E.DSCS_ID AND D.USER_ID = E.RGTR_ID AND E.DELYN = 'N' WHERE A.DELYN = 'N' AND A.USEYN = 'Y'
AND A.SBJCT_ID = #{year}
AND A.CRS_ID = #{semester}
AND ( DATE_FORMAT(E.FRST_INQ_DTTM, "%Y%m%d") BETWEEN DATE_FORMAT(#{todayDttm}, "%Y%m%d") AND DATE_FORMAT(ADDDATE(NOW(), INTERVAL 1 DAY), "%Y%m%d") )

