SELECT D.EXAM_ID , A.EXAM_TTL , E.USER_ID , D.FRST_INQ_DTTM , D.MOD_DTTM FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' JOIN TB_LMS_SBJCT C ON B.SBJCT_ID = C.SBJCT_ID AND C.DELYN = 'N' AND C.USEYN = 'Y' JOIN TB_LMS_EXAM_STARE D ON A.EXAM_ID = D.EXAM_ID AND D.DELYN = 'N' AND D.SDTTM IS NOT NULL JOIN TB_LMS_ATNDLC_SBJCT E ON D.STD_ID = E.STD_ID AND E.ATNDLC_STSCD = 'S' /* 승인상태 */ AND E.AUDITYN = 'N' /* 청강생여부 */ AND E.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND E.ORG_ID = #{orgId} WHERE A.EXAM_CTGRCD = 'QUIZ' AND A.DELYN = 'N' AND A.REG_YN = 'Y' AND A.USEYN = 'Y' AND A.ORG_ID = #{orgId}
AND C.SBJCT_ID = #{year}
AND C.CRS_ID = #{semester}
AND ( DATE_FORMAT(D.FRST_INQ_DTTM, "%Y%m%d") BETWEEN DATE_FORMAT(#{todayDttm}, "%Y%m%d") AND DATE_FORMAT(ADDDATE(NOW(), INTERVAL 1 DAY), "%Y%m%d") )

