		LIMIT #{firstIndex}, #{listScale}

mapper.sql:
SELECT E.SRVY_ID , D.SRVY_TTL , E.USER_ID , E.FRST_INQ_DTTM , E.MOD_DTTM FROM TB_LMS_SBJCT A INNER JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' /* 승인상태 */ AND B.AUDITYN = 'N' /* 청강생여부 */ AND B.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND B.ORG_ID = #{orgId} JOIN TB_LMS_RESCH_CRE_CRS_RLTN C ON A.SBJCT_ID = C.SBJCT_ID AND C.DELYN = 'N' JOIN TB_LMS_SRVY D ON C.SRVY_ID = D.SRVY_ID AND D.DELYN = 'N' AND D.USEYN = 'Y' AND D.ORG_ID = #{orgId} JOIN TB_LMS_SRVY_RSPNS E ON D.SRVY_ID = E.SRVY_ID AND B.USER_ID = E.USER_ID WHERE A.DELYN = 'N' AND A.USEYN = 'Y'
AND A.SBJCT_ID = #{year}
AND A.CRS_ID = #{semester}
AND ( DATE_FORMAT(E.FRST_INQ_DTTM, "%Y%m%d") BETWEEN DATE_FORMAT(#{todayDttm}, "%Y%m%d") AND DATE_FORMAT(ADDDATE(NOW(), INTERVAL 1 DAY), "%Y%m%d") )

mapper.select:
        /*
             SQL ID : ApiDAO.selectAcademyReschList
             설 명 : 학습활동이력 설문목록
        */

		ORDER BY E.SRVY_ID
		LIMIT #{firstIndex}, #{listScale}

mapper.sql:
SELECT B.SMNR_ID , C.USER_ID , C.ATND_STSCD , C.FRST_INQ_DTTM , C.MOD_DTTM FROM TB_LMS_SBJCT A JOIN TB_LMS_SMNR B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' JOIN TB_LMS_SMNR_ATND C ON B.SMNR_ID = C.SMNR_ID AND C.ATND_STSCD IN ( 'ATTEND' , 'LATE') JOIN TB_LMS_ATNDLC_SBJCT D ON C.STD_ID = D.STD_ID AND D.ATNDLC_STSCD = 'S' /* 승인상태 */ AND D.AUDITYN = 'N' /* 청강생여부 */ AND D.ATNDLC_ABNDYN = 'N' /* 수강포기여부 */ AND D.ORG_ID = #{orgId} JOIN TB_LMS_TERM_CRE_CRS_RLTN E ON A.SBJCT_ID = E.SBJCT_ID JOIN CRS_SMSTR F ON E.CRS_SMSTR_ID = F.CRS_SMSTR_ID AND F.ORG_ID = #{orgId} WHERE A.DELYN = 'N' AND A.USEYN = 'Y'
AND A.SBJCT_ID = #{year}
AND A.CRS_ID = #{semester}
AND ( DATE_FORMAT(C.FRST_INQ_DTTM, "%Y%m%d") BETWEEN DATE_FORMAT(#{todayDttm}, "%Y%m%d") AND DATE_FORMAT(ADDDATE(NOW(), INTERVAL 1 DAY), "%Y%m%d") )

mapper.select:
        /*
             SQL ID : ApiDAO.selectAcademySeminarList
             설 명 : 학습활동이력 세미나목록
        */

		ORDER BY B.SMNR_ID
		LIMIT #{firstIndex}, #{listScale}
